};

import React, { useState } from 'react';
import { Search, MapPin, Loader2, Zap, Info, PlusCircle, Radar, Target } from 'lucide-react';
import { Lead } from '../types';
import { searchLeadsWithGemini, enrichLeadsWithGemini } from '../services/gemini';

interface LeadFinderProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  onCallLead: (lead: Lead) => void;
}

const LeadFinder: React.FC<LeadFinderProps> = ({ leads, setLeads, onCallLead }) => {
  const [query, setQuery] = useState('Dental Clinics');
  const [location, setLocation] = useState('New York');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<Lead[]>([]);

  const handleScan = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query || !location) return;
    setLoading(true);
    setError(null);
    setResults([]);
    try {
      const { leads: fetched } = await searchLeadsWithGemini(query, location);
      if (fetched.length > 0) {
        setResults(fetched);
      } else {
        setError("No new signals found for this coordinate.");
      }
    } catch (err) {
      setError("Satellite link interrupted. Please check your system configuration.");
    } finally {
      setLoading(false);
    }
  };

  const handleIngest = async (lead: Lead) => {
    try {
      // Temporary state to show ingestion progress
      setResults(prev => prev.map(r => r.id === lead.id ? { ...r, status: 'Closed' } : r)); 
      const enriched = await enrichLeadsWithGemini([lead]);
      setLeads(prev => [...enriched, ...prev]);
      setResults(prev => prev.filter(r => r.id !== lead.id));
    } catch (e) {
      setLeads(prev => [lead, ...prev]);
      setResults(prev => prev.filter(r => r.id !== lead.id));
    }
  };

  return (
    <div className="space-y-12">
      <div className="bg-white rounded-[3rem] border-2 border-slate-100 p-12 shadow-2xl relative overflow-hidden">
        {loading && (
          <div className="absolute inset-0 bg-emerald-500/5 flex items-center justify-center z-10">
            <div className="relative">
              <div className="w-64 h-64 border-4 border-emerald-500/20 rounded-full animate-[spin_4s_linear_infinite]"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <Radar className="w-16 h-16 text-emerald-500 animate-pulse" />
              </div>
            </div>
          </div>
        )}

        <div className="max-w-4xl mx-auto space-y-10 relative z-20">
          <div className="text-center space-y-3">
            <h2 className="text-4xl font-black text-slate-950 uppercase tracking-tighter">Tactical Scout</h2>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-[0.4em]">Google Maps Grounding Protocol v3.0</p>
          </div>

          <form onSubmit={handleScan} className="flex flex-col md:flex-row gap-5">
            <div className="flex-[2] relative">
              <input 
                type="text" 
                value={query} 
                onChange={e => setQuery(e.target.value)}
                placeholder="Target Niche (e.g. Lawyers, Schools)"
                className="w-full h-20 bg-slate-50 border-4 border-slate-100 rounded-3xl px-14 font-black text-slate-800 focus:border-emerald-500 outline-none transition-all placeholder:text-slate-300"
              />
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-300" />
            </div>
            <div className="flex-1 relative">
              <input 
                type="text" 
                value={location} 
                onChange={e => setLocation(e.target.value)}
                placeholder="Region"
                className="w-full h-20 bg-slate-50 border-4 border-slate-100 rounded-3xl px-14 font-black text-slate-800 focus:border-emerald-500 outline-none transition-all placeholder:text-slate-300"
              />
              <MapPin className="absolute left-5 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-300" />
            </div>
            <button 
              disabled={loading}
              className="h-20 px-10 bg-slate-950 text-white rounded-3xl font-black uppercase text-[12px] tracking-widest flex items-center justify-center gap-4 hover:bg-emerald-600 transition-all disabled:opacity-50 shadow-xl active:scale-95"
            >
