import React, { useState } from 'react';
import { Search, MapPin, Loader2, Zap, Info, PlusCircle, Radar, Target, Download, Trash2 } from 'lucide-react';
import { Lead } from '../types';
import { searchLeadsWithGemini, enrichLeadsWithGemini } from '../services/gemini';

interface LeadFinderProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  onCallLead: (lead: Lead) => void;
}

const LeadFinder: React.FC<LeadFinderProps> = ({ leads, setLeads, onCallLead }) => {
  const [query, setQuery] = useState('Dental Clinics');
  const [location, setLocation] = useState('Nairobi, Kenya');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<Lead[]>([]);

  const handleScan = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query || !location) return;
    setLoading(true);
    setError(null);
    setResults([]);
    try {
      const { leads: fetched } = await searchLeadsWithGemini(query, location);
      if (fetched.length > 0) {
        setResults(fetched);
      } else {
        setError("No new signals found for this coordinate.");
      }
    } catch (err) {
      setError("Satellite link interrupted. Please check your system configuration.");
    } finally {
      setLoading(false);
    }
  };

  const handleIngest = async (lead: Lead) => {
    try {
      const enriched = await enrichLeadsWithGemini([lead]);
      setLeads(prev => [...enriched, ...prev]);
      setResults(prev => prev.filter(r => r.id !== lead.id));
    } catch (e) {
      setLeads(prev => [lead, ...prev]);
      setResults(prev => prev.filter(r => r.id !== lead.id));
    }
  };

  return (
    <div className="space-y-8 pb-10">
      {/* Scan Network Header - Matching Screenshot 2 */}
      <div className="bg-emerald-950 p-4 rounded-3xl flex items-center justify-center gap-3 shadow-xl">
        <Zap className="w-5 h-5 text-emerald-400 fill-current" />
        <span className="text-white font-black uppercase text-xs tracking-widest">Scan Network</span>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm space-y-6">
        <div className="space-y-4">
          <div className="relative">
            <input 
              type="text" 
              value={query} 
              onChange={e => setQuery(e.target.value)}
              placeholder="Target Niche"
              className="w-full h-16 bg-slate-50 border-2 border-slate-100 rounded-2xl px-12 font-bold text-slate-800 focus:border-emerald-500 outline-none transition-all"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
          </div>
          <div className="relative">
            <input 
              type="text" 
              value={location} 
              onChange={e => setLocation(e.target.value)}
              placeholder="Region"
              className="w-full h-16 bg-slate-50 border-2 border-slate-100 rounded-2xl px-12 font-bold text-slate-800 focus:border-emerald-500 outline-none transition-all"
            />
            <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
          </div>
          <button 
            onClick={handleScan}
            disabled={loading}
            className="w-full h-16 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-3 hover:bg-emerald-700 transition-all disabled:opacity-50"
          >
            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Search Intelligence'}
          </button>
        </div>
      </div>

      {/* Intelligence Grid - Matching Screenshot 2 */}
      <div className="space-y-6">
        <div className="flex items-center justify-between px-4">
          <div>
            <h3 className="text-xl font-black text-emerald-950 uppercase tracking-tight">Intelligence Grid</h3>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-0.5">{leads.length} Records Loaded</p>
          </div>
          <div className="flex gap-2">
            <button className="p-3 bg-white border border-slate-100 rounded-xl text-slate-400 hover:text-emerald-600 transition-all">
              <Download className="w-5 h-5" />
            </button>
            <button className="p-3 bg-white border border-slate-100 rounded-xl text-red-100 hover:text-red-500 transition-all" onClick={() => setLeads([])}>
              <Trash2 className="w-5 h-5" />
            </button>
          </div>
        </div>

        <div className="bg-white rounded-[2rem] border border-slate-100 overflow-hidden shadow-sm">
          <div className="divide-y divide-slate-50">
            {(results.length > 0 ? results : leads).map((lead) => (
              <div key={lead.id} className="p-6 space-y-4 hover:bg-slate-50/50 transition-colors">
                <div className="flex items-start gap-5">
                  <div className="w-12 h-12 bg-white border border-slate-100 rounded-xl flex items-center justify-center font-black text-xl text-slate-900 shadow-sm">
                    {lead.name.charAt(0)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="text-sm font-black text-slate-900 uppercase tracking-tight truncate">{lead.name}</h4>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1 truncate">{lead.address}</p>
                  </div>
                </div>
                <div className="flex gap-3 pt-2">
                  <button 
                    onClick={() => results.length > 0 ? handleIngest(lead) : onCallLead(lead)}
                    className="p-3 bg-emerald-900 text-emerald-400 rounded-xl hover:bg-emerald-800 transition-all shadow-lg"
                  >
                    <Zap className="w-5 h-5 fill-current" />
                  </button>
                  <button className="p-3 bg-white border border-slate-100 rounded-xl text-slate-400 hover:border-emerald-200 transition-all">
                    <PlusCircle className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default LeadFinder;

