import AnalyticsDashboard from './components/AnalyticsDashboard';
import KnowledgeBase from './components/KnowledgeBase';
import SettingsTab from './components/SettingsTab';
import { AppTab, Lead, KnowledgeNode, CallLog } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.SCOUT);
  const [activeLead, setActiveLead] = useState<Lead | null>(null);
  const [leads, setLeads] = useState<Lead[]>(() => {
    const saved = localStorage.getItem('nexus_leads');
    return saved ? JSON.parse(saved) : [];
  });
  const [callLogs, setCallLogs] = useState<CallLog[]>([]);
  const [knowledgeNodes, setKnowledgeNodes] = useState<KnowledgeNode[]>([]);

  useEffect(() => {
    localStorage.setItem('nexus_leads', JSON.stringify(leads));
  }, [leads]);

  const handleCallLead = (lead: Lead) => {
    setActiveLead(lead);
    setActiveTab(AppTab.AGENT);
  };

  const updateLead = (id: string, updates: Partial<Lead>) => {
    setLeads(prev => prev.map(l => l.id === id ? { ...l, ...updates } : l));
    if (activeLead && activeLead.id === id) {
      setActiveLead(prev => prev ? { ...prev, ...updates } : null);
    }
  };

  const addCallLog = (log: Omit<CallLog, 'id'>) => {
    setCallLogs(prev => [{ ...log, id: crypto.randomUUID() }, ...prev]);
  };

  return (
    <div className="h-screen w-full bg-[#f8fafc] text-slate-900 font-sans flex flex-col overflow-hidden">
      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-32">
        <div className="max-w-4xl mx-auto p-4 md:p-8 animate-in fade-in duration-500">
          {activeTab === AppTab.SCOUT && (
            <LeadFinder leads={leads} setLeads={setLeads} onCallLead={handleCallLead} />
          )}

          {activeTab === AppTab.INTEL && (
            <KnowledgeBase nodes={knowledgeNodes} setNodes={setKnowledgeNodes} setLeads={setLeads} />
          )}

          {activeTab === AppTab.AGENT && (
            <CallAgent 
              activeLead={activeLead} 
              leads={leads} 
              knowledgeNodes={knowledgeNodes} 
              setActiveLead={setActiveLead} 
              updateLead={updateLead} 
              onLogCall={addCallLog}
            />
          )}

          {activeTab === AppTab.DATA && (
            <AnalyticsDashboard leads={leads} onCallLead={handleCallLead} />
          )}

          {activeTab === AppTab.SETUP && (
            <SettingsTab />
          )}
        </div>
      </main>

      {/* Navigation Bar - Corrected 5-tab structure */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-2 py-3 flex items-center justify-around z-[100] shadow-[0_-4px_20px_rgba(0,0,0,0.03)]">
        <NavButton 
          active={activeTab === AppTab.SCOUT} 
          onClick={() => setActiveTab(AppTab.SCOUT)} 
          icon={Search} 
          label="SCOUT" 
        />
        <NavButton 
          active={activeTab === AppTab.INTEL} 
          onClick={() => setActiveTab(AppTab.INTEL)} 
          icon={LayoutGrid} 
          label="INTEL" 
        />
        <NavButton 
          active={activeTab === AppTab.AGENT} 
          onClick={() => setActiveTab(AppTab.AGENT)} 
          icon={Phone} 
          label="AGENT" 
        />
        <NavButton 
          active={activeTab === AppTab.DATA} 
          onClick={() => setActiveTab(AppTab.DATA)} 
          icon={Activity} 
          label="DATA" 
        />
        <NavButton 
          active={activeTab === AppTab.SETUP} 
          onClick={() => setActiveTab(AppTab.SETUP)} 
          icon={Settings} 
          label="SETUP" 
        />
      </nav>
    </div>
