      const base64Audio = await synthesizeSpeech(
        `Hello, I am your EduNexus agent. I am currently testing the ${voiceId} voice profile. How does it sound?`, 
        voiceId
      );

      if (!audioCtxRef.current) {
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const audioCtx = audioCtxRef.current;
      const uint8 = base64ToUint8Array(base64Audio);
      const buffer = await decodeAudioData(uint8, audioCtx, 24000, 1);

      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setPreviewingVoice(null);
      source.start();

    } catch (err: any) {
      console.error("Preview failed", err);

      // Handle 403 Forbidden / Permission Denied
      if (err.message?.includes('403') || err.message?.includes('permission')) {
        setError("API PERMISSION DENIED: This model requires a paid API key or specific project permissions.");
