            <span className="text-2xl font-black text-emerald-950 tracking-tight">{agentName}</span>
            <div className="flex items-center gap-2 px-4 py-2 bg-emerald-100 text-emerald-600 rounded-xl text-[10px] font-black uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">
              Primary Persona
            </div>
          </div>
        </div>
      </div>

      {/* VOCAL CORE - Selection & Listening */}
      <div className="space-y-8">
