              className="flex items-center gap-2 bg-amber-50 text-amber-700 px-4 py-2 rounded-xl border border-amber-200 text-[10px] font-black uppercase tracking-widest hover:bg-amber-100 transition-all shadow-sm"
            >
              <Key className="w-4 h-4" /> Resolve Access
            </button>
          )}
        </div>

        {error && (
