  Info, Terminal, Target, Brain, 
  Plus, Database, Search, ShieldCheck, 
  AlertCircle, ChevronRight, Loader2, Play
} from 'lucide-react';
import { KnowledgeNode, Lead } from '../types';
import { analyzeScriptEffectiveness } from '../services/gemini';

interface KnowledgeBaseProps {
  nodes: KnowledgeNode[];
  setNodes: React.Dispatch<React.SetStateAction<KnowledgeNode[]>>;
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
}

const KnowledgeBase: React.FC<KnowledgeBaseProps> = ({ nodes, setNodes }) => {
  const [instruction, setInstruction] = useState(() => {
    return localStorage.getItem('nexus_ai_instructions') || 
      "You are a helpful admissions officer for EduNexus Kenya. Your goal is to inform school administrators about our new AI platform that helps manage student admissions. Be professional, friendly, and focus on time-saving benefits.";
  });
  const [isSaving, setIsSaving] = useState(false);
  const [isTesting, setIsTesting] = useState(false);
  const [testResult, setTestResult] = useState<string | null>(null);

  const [localNodes, setLocalNodes] = useState<KnowledgeNode[]>(() => {
    const saved = localStorage.getItem('nexus_knowledge_nodes');
    return saved ? JSON.parse(saved) : [
      { id: '1', title: 'Admissions Logic', content: 'Schools prioritize enrollment numbers during Jan-Mar.', type: 'Manual', intent: 'General', isActive: true, lastUpdated: new Date().toISOString() },
      { id: '2', title: 'Pricing FAQ', content: 'Subscription starts at 15k KES per term.', type: 'Manual', intent: 'General', isActive: true, lastUpdated: new Date().toISOString() }
    ];
  });

  useEffect(() => {
    localStorage.setItem('nexus_knowledge_nodes', JSON.stringify(localNodes));
  }, [localNodes]);

  const handleSave = () => {
    setIsSaving(true);
    localStorage.setItem('nexus_ai_instructions', instruction);
    setTimeout(() => setIsSaving(false), 800);
  };

  const handleStressTest = async () => {
    setIsTesting(true);
    setTestResult(null);
    try {
      const result = await analyzeScriptEffectiveness(instruction);
      setTestResult(result);
    } catch (e) {
      setTestResult("Critical failure in Neural Evaluation loop.");
    } finally {
      setIsTesting(false);
    }
  };

  const templates = [
    { name: 'Admissions Pro', text: 'You are a professional Admissions Director. Your tone is authoritative yet welcoming. Focus on enrollment KPIs.' },
    { name: 'Concierge AI', text: 'You are a friendly concierge assistant. Your goal is to answer basic questions and schedule a deep-dive meeting.' },
    { name: 'Consultative Sales', text: 'You are an educational technology consultant. Focus on solving administrative pain points and data security.' }
  ];

  const calculateScore = () => {
    const len = instruction.length;
    if (len < 50) return 20;
    if (len < 150) return 50;
    if (len < 300) return 85;
    return 100;
  };

  return (
    <div className="space-y-12 pb-32 animate-in fade-in duration-700">
      {/* INTEL NODE Header */}
      <div className="flex flex-col md:flex-row justify-between items-end gap-6">
        <div className="space-y-4">
          <h1 className="text-7xl font-black text-emerald-950 tracking-tighter uppercase leading-[0.8] flex items-center gap-4">
            Intel <Brain className="w-16 h-16 text-emerald-500/20" />
          </h1>
          <p className="text-xl font-bold text-slate-400 leading-relaxed max-w-xl uppercase tracking-tighter">
            Neural Command Center
          </p>
        </div>

        <div className="flex items-center gap-4 bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm">
           <div className="flex flex-col items-end">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Instruction Density</span>
              <span className="text-2xl font-black text-emerald-600 uppercase tracking-tighter">{calculateScore()}%</span>
           </div>
           <div className="w-12 h-12 rounded-full border-4 border-emerald-50 flex items-center justify-center">
              <div 
                className="w-8 h-8 rounded-full bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)] animate-pulse" 
                style={{ opacity: calculateScore() / 100 }}
              />
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Main Logic Panel */}
        <div className="lg:col-span-8 space-y-8">
          <div className="bg-white rounded-[3.5rem] border-4 border-slate-100 p-8 md:p-14 shadow-2xl shadow-slate-200/50 space-y-10 relative overflow-hidden">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-5">
                <div className="p-5 bg-emerald-900 text-emerald-400 rounded-3xl shadow-xl">
                  <Terminal className="w-10 h-10" />
                </div>
                <div>
                  <h2 className="text-4xl font-black text-emerald-950 uppercase tracking-tighter leading-none">Injunction</h2>
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mt-2">Primary Logic Control</p>
                </div>
              </div>

              <div className="flex gap-2">
                 <button 
                  onClick={handleStressTest}
                  disabled={isTesting}
                  className="p-5 bg-slate-50 text-slate-400 rounded-3xl hover:bg-emerald-50 hover:text-emerald-600 transition-all border border-slate-100 group"
                  title="Stress Test AI Logic"
                 >
                   {isTesting ? <Loader2 className="w-6 h-6 animate-spin" /> : <Play className="w-6 h-6 fill-current group-hover:scale-110" />}
                 </button>
                 <button 
                  onClick={handleSave}
                  disabled={isSaving}
                  className="flex items-center gap-3 bg-emerald-950 text-white px-10 py-5 rounded-3xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-black shadow-2xl transition-all active:scale-95"
                 >
                  {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                  Deploy
                 </button>
              </div>
            </div>

            <div className="relative group">
              <textarea 
                value={instruction}
                onChange={(e) => setInstruction(e.target.value)}
                placeholder="Initialize agent directive..."
                className="w-full h-[450px] bg-slate-50 border-4 border-slate-50 rounded-[3rem] p-12 text-xl font-bold text-slate-800 focus:border-emerald-500 focus:bg-white outline-none transition-all shadow-inner resize-none leading-relaxed"
              />
              <div className="absolute bottom-8 left-10 flex items-center gap-3 px-6 py-3 bg-white rounded-2xl border border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest shadow-sm">
                 <ShieldCheck className="w-3 h-3 text-emerald-500" /> Neural Sandbox: Ready
              </div>
            </div>

            {testResult && (
              <div className="p-10 bg-emerald-50 rounded-[3rem] border-2 border-emerald-100 animate-in slide-in-from-top-4 duration-500 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4">
                  <button onClick={() => setTestResult(null)} className="text-emerald-300 hover:text-emerald-500 transition-colors">
                    <X className="w-6 h-6" />
                  </button>
                </div>
                <h4 className="text-sm font-black text-emerald-900 uppercase tracking-widest mb-6 flex items-center gap-3">
                  <Zap className="w-5 h-5 fill-current" /> Stress Test Findings
                </h4>
                <div className="prose prose-sm prose-emerald max-w-none text-emerald-800 font-bold" dangerouslySetInnerHTML={{ __html: testResult.replace(/\n/g, '<br/>') }} />
              </div>
            )}
          </div>
        </div>

        {/* Knowledge Nodes Sidebar */}
        <div className="lg:col-span-4 space-y-8">
           <div className="bg-emerald-950 p-10 rounded-[3.5rem] text-white shadow-2xl space-y-8 h-full">
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-xl font-black uppercase tracking-tighter text-emerald-400">Knowledge Chips</h3>
                  <p className="text-[9px] font-black text-emerald-500/60 uppercase tracking-widest mt-1">Grounding Context</p>
                </div>
                <button className="p-3 bg-white/10 rounded-2xl hover:bg-white/20 transition-all">
                  <Plus className="w-6 h-6" />
                </button>
              </div>

              <div className="space-y-4">
                {localNodes.map((node) => (
                  <div key={node.id} className="p-6 bg-white/5 rounded-3xl border border-white/10 hover:border-emerald-500/50 transition-all cursor-pointer group">
                    <div className="flex items-center justify-between mb-3">
                      <div className="p-2 bg-emerald-500/10 text-emerald-400 rounded-lg">
                        <Database className="w-4 h-4" />
                      </div>
                      <span className="text-[8px] font-black uppercase text-emerald-500/40">Active</span>
                    </div>
                    <h4 className="text-xs font-black uppercase tracking-widest group-hover:text-emerald-400 transition-colors">{node.title}</h4>
                    <p className="text-[10px] font-bold text-white/40 mt-2 leading-relaxed truncate">{node.content}</p>
                  </div>
                ))}
              </div>

              <div className="pt-8 border-t border-white/10 space-y-6">
                <h3 className="text-[10px] font-black uppercase tracking-[0.3em] text-emerald-500/60">Persona Presets</h3>
                <div className="space-y-3">
                  {templates.map((t) => (
                    <button 
                      key={t.name}
                      onClick={() => setInstruction(t.text)}
                      className="w-full p-5 bg-white/5 rounded-2xl border border-white/5 hover:bg-emerald-500 hover:text-emerald-950 text-left transition-all flex items-center justify-between group"
                    >
                      <span className="text-[11px] font-black uppercase tracking-widest">{t.name}</span>
                      <ChevronRight className="w-4 h-4 opacity-0 group-hover:opacity-100 transition-all" />
                    </button>
                  ))}
                </div>
              </div>

              <div className="bg-emerald-900/50 p-6 rounded-3xl border border-white/5 flex items-start gap-4">
                 <AlertCircle className="w-5 h-5 text-emerald-400 shrink-0 mt-0.5" />
                 <p className="text-[9px] font-bold text-emerald-300 uppercase leading-relaxed tracking-wide">
                   Nodes are automatically injected into the AI context window during sync.
                 </p>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

const X = ({ className }: { className?: string }) => (
  <svg className={className} width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
    <path d="M18 6L6 18M6 6l12 12" />
  </svg>
);

export default KnowledgeBase;

import React, { useState, useRef } from 'react';
import { 
  FileText, PenTool, Upload, Brain, 
  Zap, Search, CheckCircle, Loader2, 
  AlertCircle, ChevronRight, X, Sparkles
} from 'lucide-react';
import { KnowledgeNode, Lead } from '../types';
import { analyzeScriptEffectiveness } from '../services/gemini';

interface KnowledgeBaseProps {
  nodes: KnowledgeNode[];
  setNodes: React.Dispatch<React.SetStateAction<KnowledgeNode[]>>;
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
}

const KnowledgeBase: React.FC<KnowledgeBaseProps> = () => {
  const [sourceType, setSourceType] = useState<'write' | 'upload'>('write');
  const [content, setContent] = useState(() => {
    return localStorage.getItem('nexus_ai_instructions') || "";
  });
  const [isScanning, setIsScanning] = useState(false);
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [fileName, setFileName] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleScan = async () => {
    if (!content && !fileName) return;
    setIsScanning(true);
    setAnalysis(null);

    try {
      // Use Gemini to "Understand and Scan" the content
      const result = await analyzeScriptEffectiveness(content || `Analyzing uploaded file: ${fileName}`);
      setAnalysis(result);
      localStorage.setItem('nexus_ai_instructions', content);
    } catch (e) {
      setAnalysis("System calibration failed. Please try again.");
    } finally {
      setIsScanning(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFileName(file.name);
      setSourceType('upload');
      // Simulate reading content
      setContent(`Processed Content from ${file.name}: Lead outreach for regional managers focusing on performance metrics.`);
    }
  };

  const clear = () => {
    setContent("");
    setFileName(null);
    setAnalysis(null);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 pb-32 animate-in fade-in duration-700">
      {/* Dynamic Header */}
      <div className="text-center space-y-4">
        <div className="inline-flex p-4 bg-emerald-950 text-emerald-400 rounded-3xl shadow-2xl mb-4">
          <Brain className="w-10 h-10" />
        </div>
        <h1 className="text-5xl font-black text-slate-900 tracking-tighter uppercase">
          Intent <span className="text-emerald-500">Core</span>
        </h1>
        <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">
          Define what the AI says and understands
        </p>
      </div>

      {/* Input Selector */}
      <div className="flex justify-center gap-4">
        <button 
          onClick={() => setSourceType('write')}
          className={`px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center gap-3 ${
            sourceType === 'write' ? 'bg-emerald-900 text-white shadow-xl scale-105' : 'bg-white text-slate-400 border border-slate-100'
          }`}
        >
          <PenTool className="w-4 h-4" /> Write Directive
        </button>
        <button 
          onClick={() => fileInputRef.current?.click()}
          className={`px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center gap-3 ${
            sourceType === 'upload' ? 'bg-emerald-900 text-white shadow-xl scale-105' : 'bg-white text-slate-400 border border-slate-100'
          }`}
        >
          <Upload className="w-4 h-4" /> Upload Doc
        </button>
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          onChange={handleFileUpload}
          accept=".txt,.pdf,.doc,.docx"
        />
      </div>

      {/* Main Action Area */}
      <div className="bg-white rounded-[3.5rem] border border-slate-100 p-8 md:p-12 shadow-sm space-y-8 relative overflow-hidden">
        {sourceType === 'write' ? (
          <div className="space-y-6">
            <textarea 
              value={content}
              onChange={(e) => setContent(e.target.value)}
              placeholder="What should the AI talk about? (e.g., Calling schools to offer software demos...)"
              className="w-full h-64 bg-slate-50 border-4 border-slate-50 rounded-[2.5rem] p-10 text-xl font-bold text-slate-800 focus:border-emerald-500 focus:bg-white outline-none transition-all resize-none leading-relaxed placeholder:text-slate-200"
            />
          </div>
        ) : (
          <div 
            className="w-full h-64 bg-emerald-50 border-4 border-dashed border-emerald-100 rounded-[2.5rem] flex flex-col items-center justify-center p-10 text-center space-y-4 cursor-pointer hover:bg-emerald-100/50 transition-all"
            onClick={() => fileInputRef.current?.click()}
          >
            {fileName ? (
              <>
                <div className="p-4 bg-white rounded-2xl text-emerald-500 shadow-sm">
                  <FileText className="w-10 h-10" />
                </div>
                <p className="text-xl font-black text-emerald-900 tracking-tight uppercase">{fileName}</p>
                <button onClick={(e) => { e.stopPropagation(); clear(); }} className="text-[10px] font-black text-emerald-600 uppercase tracking-widest hover:underline">Remove</button>
              </>
            ) : (
              <>
                <Upload className="w-12 h-12 text-emerald-200" />
                <p className="text-sm font-bold text-emerald-400 uppercase tracking-widest">Drop your strategy document here</p>
              </>
            )}
          </div>
        )}

        {/* Scan Button */}
        <button 
          onClick={handleScan}
          disabled={isScanning || (!content && !fileName)}
          className="w-full py-8 bg-emerald-600 text-white rounded-[2rem] font-black uppercase text-lg tracking-[0.3em] shadow-2xl hover:bg-emerald-700 transition-all disabled:opacity-30 flex items-center justify-center gap-4 relative overflow-hidden group"
        >
          {isScanning ? (
            <>
              <Loader2 className="w-8 h-8 animate-spin" />
              Scanning Neural pathways...
            </>
          ) : (
            <>
              <Zap className="w-6 h-6 fill-current" />
              Sync & Understand
            </>
          )}
          <div className="absolute inset-0 bg-white/20 -translate-x-full group-hover:translate-x-0 transition-transform duration-700"></div>
        </button>
      </div>

      {/* Analysis Output */}
      {analysis && (
        <div className="animate-in slide-in-from-bottom-8 duration-500 space-y-8">
          <div className="flex items-center gap-4 px-4">
             <Sparkles className="w-5 h-5 text-emerald-500" />
             <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">AI Context Extracted</h3>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-emerald-950 p-10 rounded-[3rem] text-white shadow-xl border border-white/5 space-y-6">
              <div className="flex items-center justify-between">
                <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Logic Breakdown</span>
                <CheckCircle className="w-4 h-4 text-emerald-400" />
              </div>
              <div 
                className="prose prose-invert prose-sm max-w-none font-bold text-emerald-100/80 leading-relaxed"
                dangerouslySetInnerHTML={{ __html: analysis.replace(/\n/g, '<br/>') }}
              />
            </div>

            <div className="space-y-6">
               <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-6 group hover:border-emerald-200 transition-all">
                  <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl group-hover:bg-emerald-600 group-hover:text-white transition-all">
                    <Target className="w-6 h-6" />
                  </div>
                  <div>
                    <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Intent Verified</h4>
                    <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">AI has locked onto the objective</p>
                  </div>
               </div>

               <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-6 group hover:border-blue-200 transition-all">
                  <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl group-hover:bg-blue-600 group-hover:text-white transition-all">
                    <Database className="w-6 h-6" />
                  </div>
                  <div>
                    <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Context Ingested</h4>
                    <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">Data synced to short-term memory</p>
                  </div>
               </div>

               <div className="bg-emerald-50 p-8 rounded-[2.5rem] border border-emerald-100 flex items-center gap-4">
                  <AlertCircle className="w-5 h-5 text-emerald-500 shrink-0" />
                  <p className="text-[10px] font-black text-emerald-900 uppercase leading-relaxed tracking-tight">
                    The Agent is now programmed. You can initiate a call from the AGENT tab.
                  </p>
               </div>
            </div>
          </div>
        </div>
      )}

      {/* Empty State */}
      {!analysis && !isScanning && (
        <div className="p-20 text-center border-4 border-dashed border-slate-100 rounded-[4rem] opacity-30">
          <Search className="w-12 h-12 text-slate-300 mx-auto mb-4" />
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Awaiting Instruction Input</p>
        </div>
      )}
    </div>
  );
};

export default KnowledgeBase;

