import React, { useState, useRef } from 'react';
import { Volume2, Edit3, Play, Headphones, CheckCircle2, Zap, Loader2, AlertCircle, Key } from 'lucide-react';
import { Lead } from '../types';
import { synthesizeSpeech } from '../services/gemini';
import { base64ToUint8Array, decodeAudioData } from '../utils/audioUtils';

interface CallAgentProps {
  activeLead: Lead | null;
  selectedVoice: string;
  setSelectedVoice: (voice: string) => void;
}

const VOICES = [
  { id: 'Zephyr', label: 'ZEPHYR', desc: 'Warm, professional, balanced' },
  { id: 'Puck', label: 'PUCK', desc: 'Energetic, youth-oriented' },
  { id: 'Kore', label: 'KORE', desc: 'Calm, authoritative, clear' },
  { id: 'Charon', label: 'CHARON', desc: 'Deep, steady, reassuring' },
  { id: 'Fenrir', label: 'FENRIR', desc: 'Sharp, fast-paced, precise' }
];

const CallAgent: React.FC<CallAgentProps> = ({ selectedVoice, setSelectedVoice }) => {
  const [agentName] = useState('Nexus Assistant');
  const [previewingVoice, setPreviewingVoice] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);

  const handlePreview = async (e: React.MouseEvent, voiceId: string) => {
    e.stopPropagation();
    if (previewingVoice) return;

    setPreviewingVoice(voiceId);
    setError(null);

    try {
      const base64Audio = await synthesizeSpeech(
        `Testing the ${voiceId} profile. Systems operating within optimal parameters.`, 
        voiceId
      );

      if (!audioCtxRef.current) {
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const audioCtx = audioCtxRef.current;
      const uint8 = base64ToUint8Array(base64Audio);
      const buffer = await decodeAudioData(uint8, audioCtx, 24000, 1);

      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setPreviewingVoice(null);
      source.start();

    } catch (err: any) {
      console.error("Preview failed", err);
      setError("Voice synthesis module failed. Check API key status.");
      setPreviewingVoice(null);
    }
  };

  const openKeySelection = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setError(null);
    }
  };

  return (
    <div className="space-y-12 pb-20 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="text-center space-y-4">
        <div className="inline-flex p-4 bg-emerald-950 text-emerald-400 rounded-3xl shadow-2xl mb-4">
          <Headphones className="w-10 h-10" />
        </div>
        <h1 className="text-5xl font-black text-slate-900 tracking-tighter uppercase">
          Neural <span className="text-emerald-500">Voices</span>
        </h1>
        <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">
          Configure vocal identity and personality
        </p>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 p-8 shadow-sm space-y-8">
        <div className="flex items-center justify-between px-2">
          <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">Active Persona</h2>
          <div className="flex items-center gap-2 px-4 py-2 bg-emerald-50 text-emerald-600 rounded-xl text-[9px] font-black uppercase tracking-widest">
            <Zap className="w-3 h-3 fill-current" /> Core System
          </div>
        </div>
        <div className="bg-slate-50 border-2 border-slate-100 p-8 rounded-[2.5rem] flex items-center justify-between shadow-inner">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 bg-white rounded-2xl border border-slate-100 flex items-center justify-center">
              <Edit3 className="w-8 h-8 text-slate-300" />
            </div>
            <div>
              <span className="text-2xl font-black text-slate-900 tracking-tight">{agentName}</span>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Primary Agent Designation</p>
            </div>
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Available Voice Profiles</h3>
          {error && (
            <button onClick={openKeySelection} className="text-[9px] font-black text-amber-600 uppercase underline">Resolve Access</button>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {VOICES.map((v) => (
            <div key={v.id} className="relative">
              <button 
                onClick={() => setSelectedVoice(v.id)}
                className={`w-full p-8 rounded-[2.5rem] border-4 flex flex-col items-start transition-all group ${
                  selectedVoice === v.id 
                    ? 'bg-emerald-950 border-emerald-950 text-white shadow-2xl' 
                    : 'bg-white border-slate-100 text-slate-400 hover:border-emerald-200'
                }`}
              >
                <div className="flex items-center gap-3 mb-2">
                  <Volume2 className={`w-6 h-6 ${selectedVoice === v.id ? 'text-emerald-400' : 'text-slate-200'}`} />
                  <span className="text-lg font-black uppercase tracking-tighter">{v.label}</span>
                </div>
                <span className="text-[10px] font-bold uppercase tracking-tight opacity-50">{v.desc}</span>

                {selectedVoice === v.id && (
                  <div className="absolute top-8 right-8 text-emerald-400 animate-in zoom-in duration-300">
                    <CheckCircle2 className="w-8 h-8" />
                  </div>
                )}
              </button>

              <button 
                onClick={(e) => handlePreview(e, v.id)}
                disabled={previewingVoice !== null}
                className={`absolute -bottom-2 -right-2 w-12 h-12 rounded-full flex items-center justify-center text-white shadow-xl transition-all hover:scale-110 z-10 border-4 border-white ${
                  previewingVoice === v.id ? 'bg-emerald-600' : 'bg-emerald-500 hover:bg-emerald-600'
                }`}
              >
                {previewingVoice === v.id ? (
                  <Loader2 className="w-5 h-5 animate-spin" />
                ) : (
                  <Play className="w-5 h-5 fill-current ml-0.5" />
                )}
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

