interface CallInterfaceProps {
  activeLead: Lead | null;
  selectedVoice: string;
}

const CallInterface: React.FC<CallInterfaceProps> = ({ activeLead, selectedVoice }) => {
  const [callMode, setCallMode] = useState<'web' | 'phone'>('web');
  const [isCalling, setIsCalling] = useState(false);
  const [callTime, setCallTime] = useState(0);

  useEffect(() => {
    let interval: number;
    if (isCalling) {
      interval = window.setInterval(() => {
        setCallTime(prev => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isCalling]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleStartCall = () => {
    setIsCalling(true);
    setCallTime(0);
  };

  const handleEndCall = () => {
    setIsCalling(false);
  };

  if (!activeLead) {
    return (
      <div className="p-20 text-center bg-slate-50 rounded-[4rem] border-4 border-dashed border-slate-100 opacity-60">
