              const source = outCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onclose: () => {
            setIsLiveActive(false);
            setIsCalling(false);
          },
          onerror: () => {
            setIsLiveActive(false);
            setIsCalling(false);
          }
        }
      });
    } catch (e) {
      console.error("Neural Link failed", e);
      setIsLiveActive(false);
      setIsCalling(false);
    }
  };

  const stopLiveSession = () => {
    sessionRef.current?.close();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
    setIsLiveActive(false);
  };

  const handleStartCall = () => {
    setIsCalling(true);
    setCallTime(0);
    if (callMode === 'neural') {
      startLiveSession();
    } else if (telephonySubMode === 'swarm') {
      // Initialize swarm sequence
      const targets = swarmTargets.map(t => ({ ...t, status: 'Pending' as const }));
      setSwarmTargets(targets);
      processSwarm(targets);
    }
  };

  const processSwarm = async (targets: SwarmTarget[]) => {
    // Simulated Swarm execution
    for (let i = 0; i < targets.length; i++) {
      if (!isCalling) break;
      const updated = [...targets];
      updated[i].status = 'Calling';
      setSwarmTargets([...updated]);

      await new Promise(r => setTimeout(r, 4000)); // Simulate call duration

      updated[i].status = Math.random() > 0.2 ? 'Completed' : 'Failed';
      setSwarmTargets([...updated]);
    }
    setIsCalling(false);
  };

  const handleEndCall = () => {
    setIsCalling(false);
    if (callMode === 'neural') stopLiveSession();
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualEntry.name) return;
