export default CallInterface;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Phone, PhoneCall, Mic2, X, Zap, Loader2, 
  PhoneOff, Globe, Signal, User, 
  Plus, Database, MessageSquare,
  Volume2, Mic, Activity, Users, 
  CheckCircle2, Play, MousePointer2
} from 'lucide-react';
import { Lead, SwarmTarget } from '../types';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { base64ToUint8Array, decodeAudioData } from '../utils/audioUtils';

interface CallInterfaceProps {
  activeLead: Lead | null;
  selectedVoice: string;
}

const CallInterface: React.FC<CallInterfaceProps> = ({ activeLead: initialLead, selectedVoice }) => {
  const [activeLead, setActiveLead] = useState<Lead | null>(initialLead);
  const [mode, setMode] = useState<'selection' | 'web' | 'phone' | 'bulk'>('selection');
  const [isCalling, setIsCalling] = useState(false);
  const [callTime, setCallTime] = useState(0);

  // Inputs
  const [manualEntry, setManualEntry] = useState({ name: '', phone: '' });
  const [bulkInput, setBulkInput] = useState('');
  const [bulkTargets, setBulkTargets] = useState<SwarmTarget[]>([]);

  // Live API State (AI Conversation)
  const [isLiveActive, setIsLiveActive] = useState(false);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    if (initialLead) {
      setActiveLead(initialLead);
      setMode('phone');
    }
  }, [initialLead]);

  useEffect(() => {
    let interval: number;
    if (isCalling) {
      interval = window.setInterval(() => {
        setCallTime(prev => prev + 1);
      }, 1000);
    }
    return () => {
      clearInterval(interval);
      if (isLiveActive) stopLiveSession();
    };
  }, [isCalling, isLiveActive]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // --- AI CONVERSATION (LIVE SESSION) LOGIC ---
  const startLiveSession = async () => {
    if (!process.env.API_KEY) return;

    setIsLiveActive(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const outCtx = audioCtxRef.current;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const instructions = localStorage.getItem('nexus_ai_instructions') || "You are a helpful assistant. Have a friendly conversation with the user.";

      sessionRef.current = await ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } }
          },
          systemInstruction: instructions
        },
        callbacks: {
          onopen: () => {
            const source = inCtx.createMediaStreamSource(stream);
            const processor = inCtx.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionRef.current?.sendRealtimeInput({ 
                media: { data: base64, mimeType: 'audio/pcm;rate=16000' } 
              });
            };
            source.connect(processor);
            processor.connect(inCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const uint8 = new Uint8Array(atob(audioData).split('').map(c => c.charCodeAt(0)));
              const buffer = await decodeAudioData(uint8, outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onclose: () => {
            setIsLiveActive(false);
            setIsCalling(false);
          },
          onerror: () => {
            setIsLiveActive(false);
            setIsCalling(false);
          }
        }
      });
    } catch (e) {
      console.error("AI connection failed", e);
      setIsLiveActive(false);
      setIsCalling(false);
    }
  };

  const stopLiveSession = () => {
    sessionRef.current?.close();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
    setIsLiveActive(false);
  };

  const handleStartCall = () => {
    setIsCalling(true);
    setCallTime(0);
    if (mode === 'web') {
      startLiveSession();
    } else if (mode === 'bulk') {
      executeBulk();
    }
  };

