          </div>

          {!isCalling && mode === 'web' && (
            <div className="p-8 bg-emerald-50 rounded-[2.5rem] border border-emerald-100 text-left max-w-md animate-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center gap-3 mb-3">
                <div className="p-2 bg-emerald-100 rounded-lg text-emerald-600">
