                   <span className="text-sm font-black text-blue-800 uppercase tracking-tight">Phone Line Protocol</span>
                </div>
                <p className="text-xs text-blue-700/80 font-bold leading-relaxed">
                   Initiating a standard outbound call to <b>{activeLead?.phone}</b>. The system will bridge your voice via the neural cloud.
                </p>
             </div>
          )}

          {/* Call Controls */}
          <div className="w-full max-w-sm">
            {isCalling ? (
              <button 
                onClick={handleEndCall}
                className="w-full h-24 bg-red-500 hover:bg-red-600 text-white rounded-[2rem] flex items-center justify-center gap-5 font-black uppercase text-lg tracking-[0.2em] shadow-2xl shadow-red-100 transition-all active:scale-95 group"
