            ) : (
              <button 
                onClick={handleStartCall}
                className={`w-full h-24 rounded-[2rem] flex items-center justify-center gap-5 font-black uppercase text-lg tracking-[0.2em] shadow-2xl transition-all active:scale-95 text-white relative overflow-hidden group ${mode === 'web' ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-100' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-100'}`}
              >
                <div className="absolute inset-0 bg-white/20 -translate-x-full group-hover:translate-x-0 transition-transform duration-500"></div>
                {mode === 'web' ? <Mic2 className="w-7 h-7 relative z-10" /> : <Play className="w-7 h-7 relative z-10" />}
                <span className="relative z-10">
                  {mode === 'web' ? 'Start AI Chat' : (mode === 'bulk' ? 'Start Batch' : 'Start Call')}
                </span>
              </button>
            )}
          </div>

          {!isCalling && (
            <div className="flex flex-wrap justify-center gap-6">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                <Volume2 className="w-4 h-4 text-emerald-500" /> Voice: {selectedVoice}
              </div>
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                <Globe className="w-4 h-4 text-blue-500" /> Uplink: Stable
              </div>
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                <Activity className="w-4 h-4 text-amber-500" /> Latency: 22ms
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Bulk Call Status List */}
      {mode === 'bulk' && bulkTargets.length > 0 && (
        <div className="bg-white border border-slate-200 rounded-[3rem] p-8 space-y-6 animate-in slide-in-from-bottom-6 duration-700">
          <div className="flex items-center justify-between px-2">
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-tighter">Execution Logs</h3>
            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Live Updates</span>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {bulkTargets.map((t, i) => (
              <div key={i} className={`p-4 rounded-2xl flex items-center justify-between border transition-all ${t.status === 'Completed' ? 'bg-emerald-50 border-emerald-100' : 'bg-slate-50 border-slate-100'}`}>
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-xs ${t.status === 'Completed' ? 'bg-emerald-100 text-emerald-600' : 'bg-white text-slate-400'}`}>
                    {i + 1}
                  </div>
                  <div className="flex flex-col">
                    <span className="text-xs font-black text-slate-700 uppercase tracking-tight">{t.phone}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase">Target Coordinate</span>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <span className={`text-[10px] font-black uppercase tracking-tighter ${
                    t.status === 'Completed' ? 'text-emerald-500' : 
                    t.status === 'Calling' ? 'text-blue-500 animate-pulse' : 
                    t.status === 'Failed' ? 'text-red-500' : 'text-slate-300'
                  }`}>
                    {t.status}
                  </span>
                  {t.status === 'Completed' && <CheckCircle2 className="w-4 h-4 text-emerald-500" />}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default CallInterface;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Phone, PhoneCall, Mic2, X, Zap, Loader2, 
  PhoneOff, Globe, Signal, User, 
  Plus, Database, MessageSquare,
  Volume2, Mic, Activity, Users, 
  CheckCircle2, Play, MousePointer2,
  Waves, Headset, Info, ChevronDown
} from 'lucide-react';
import { Lead, SwarmTarget } from '../types';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { base64ToUint8Array, decodeAudioData } from '../utils/audioUtils';

interface CallInterfaceProps {
  activeLead: Lead | null;
  selectedVoice: string;
}

const VOICES = [
  { id: 'Zephyr', label: 'Zephyr (Professional)' },
  { id: 'Puck', label: 'Puck (Energetic)' },
  { id: 'Kore', label: 'Kore (Calm)' },
  { id: 'Charon', label: 'Charon (Steady)' },
  { id: 'Fenrir', label: 'Fenrir (Sharp)' }
];

const CallInterface: React.FC<CallInterfaceProps> = ({ activeLead: initialLead, selectedVoice: initialVoice }) => {
  const [activeLead, setActiveLead] = useState<Lead | null>(initialLead);
  const [mode, setMode] = useState<'selection' | 'web' | 'phone' | 'bulk'>('selection');
  const [isCalling, setIsCalling] = useState(false);
  const [callTime, setCallTime] = useState(0);
  const [currentVoice, setCurrentVoice] = useState(initialVoice);

  // Inputs
  const [manualEntry, setManualEntry] = useState({ name: '', phone: '' });
  const [bulkInput, setBulkInput] = useState('');
  const [bulkTargets, setBulkTargets] = useState<SwarmTarget[]>([]);

  // Live API State (AI Conversation)
  const [isLiveActive, setIsLiveActive] = useState(false);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    if (initialLead) {
      setActiveLead(initialLead);
      setMode('phone');
    }
  }, [initialLead]);

  useEffect(() => {
    let interval: number;
    if (isCalling) {
      interval = window.setInterval(() => {
        setCallTime(prev => prev + 1);
      }, 1000);
    }
    return () => {
      clearInterval(interval);
      if (isLiveActive) stopLiveSession();
    };
  }, [isCalling, isLiveActive]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // --- AI CONVERSATION (LIVE SESSION) LOGIC ---
  const startLiveSession = async () => {
    if (!process.env.API_KEY) {
      alert("API Key missing. Please configure your environment.");
      setIsCalling(false);
      return;
    }

    setIsLiveActive(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const outCtx = audioCtxRef.current;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const instructions = localStorage.getItem('nexus_ai_instructions') || "You are a friendly AI assistant. Talk to the user naturally.";

      sessionRef.current = await ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: currentVoice } }
          },
          systemInstruction: instructions
        },
        callbacks: {
          onopen: () => {
            console.log("AI Bridge Connected");
            const source = inCtx.createMediaStreamSource(stream);
            const processor = inCtx.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionRef.current?.sendRealtimeInput({ 
                media: { data: base64, mimeType: 'audio/pcm;rate=16000' } 
              });
            };
            source.connect(processor);
            processor.connect(inCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const uint8 = base64ToUint8Array(audioData);
              const buffer = await decodeAudioData(uint8, outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onclose: () => {
            setIsLiveActive(false);
            setIsCalling(false);
          },
          onerror: (err) => {
            console.error("AI Bridge Error", err);
            setIsLiveActive(false);
            setIsCalling(false);
          }
        }
      });
    } catch (e) {
      console.error("Mic access or AI connection failed", e);
      alert("Could not start Web Call. Please check your microphone permissions.");
      setIsLiveActive(false);
      setIsCalling(false);
    }
  };

  const stopLiveSession = () => {
    sessionRef.current?.close();
    sourcesRef.current.forEach(s => {
      try { s.stop(); } catch(e) {}
    });
    sourcesRef.current.clear();
    setIsLiveActive(false);
  };

  const handleStartCall = () => {
    setIsCalling(true);
    setCallTime(0);
    if (mode === 'web') {
      startLiveSession();
    } else if (mode === 'bulk') {
      executeBulk();
    }
    // For standard 'phone' mode, it's just a simulation timer
  };

  const executeBulk = async () => {
    const targets = bulkTargets.map(t => ({ ...t, status: 'Pending' as const }));
    setBulkTargets(targets);

    for (let i = 0; i < targets.length; i++) {
      if (!isCalling) break;
      const updated = [...targets];
      updated[i].status = 'Calling';
      setBulkTargets([...updated]);

      await new Promise(r => setTimeout(r, 3000));

      updated[i].status = Math.random() > 0.1 ? 'Completed' : 'Failed';
      setBulkTargets([...updated]);
    }
    setIsCalling(false);
  };

  const handleEndCall = () => {
    setIsCalling(false);
    if (mode === 'web') stopLiveSession();
  };

  const handleManualCall = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualEntry.name || !manualEntry.phone) return;
    setActiveLead({
      id: crypto.randomUUID(),
      name: manualEntry.name,
      phone: manualEntry.phone,
      address: 'Direct Entry',
      type: 'Phone Call',
      status: 'New'
    });
    setMode('phone');
  };

  const handleBulkSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numbers = bulkInput.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 0);
    if (numbers.length === 0) return;

    const targets: SwarmTarget[] = numbers.map((n, idx) => ({
      id: `bulk-${idx}`,
      name: `Target ${idx + 1}`,
      phone: n,
      status: 'Pending'
    }));
    setBulkTargets(targets);
    setMode('bulk');
    setActiveLead(null);
  };

  // --- SELECTION UI ---
  if (mode === 'selection') {
    const savedLeads = JSON.parse(localStorage.getItem('nexus_leads') || '[]');

    return (
      <div className="max-w-4xl mx-auto space-y-10 pb-20 animate-in fade-in duration-500">
        <div className="text-center space-y-3">
          <h1 className="text-4xl font-extrabold text-slate-900">Start a Call</h1>
          <p className="text-slate-500 font-medium">Simple outreach tools for your leads.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Web Call Section */}
          <div className="flex flex-col space-y-4">
            <button 
              onClick={() => {
                setMode('web');
                setActiveLead({ id: 'ai', name: 'AI Partner', address: 'Local', type: 'Web Call', status: 'New' });
              }}
              className="p-10 bg-white border-2 border-slate-100 rounded-[2.5rem] hover:border-emerald-500 hover:shadow-xl transition-all flex flex-col items-center text-center space-y-6 group active:scale-95"
            >
              <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-3xl flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all">
                <Mic2 className="w-10 h-10" />
              </div>
              <div>
                <h3 className="text-2xl font-bold text-slate-900">Web Call</h3>
                <p className="text-sm text-slate-500 mt-2">Talk directly with the AI in your browser. No phone number needed.</p>
              </div>
              <div className="w-full h-px bg-slate-50"></div>
              <div className="text-[10px] font-black uppercase text-emerald-500 tracking-[0.2em]">Live Conversation</div>
            </button>
          </div>

          {/* Phone Call Section */}
          <div className="p-10 bg-white border-2 border-slate-100 rounded-[2.5rem] space-y-6 shadow-sm">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center">
                <PhoneCall className="w-6 h-6" />
              </div>
              <h3 className="text-xl font-bold text-slate-900">Phone Call</h3>
            </div>

            <form onSubmit={handleManualCall} className="space-y-3">
              <div className="flex gap-2">
                <input 
                  placeholder="Name"
                  className="w-full bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none focus:border-blue-500 transition-all text-sm font-bold"
                  value={manualEntry.name}
                  onChange={e => setManualEntry({...manualEntry, name: e.target.value})}
                />
                <input 
                  placeholder="Number"
                  className="w-full bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none focus:border-blue-500 transition-all text-sm font-bold"
                  value={manualEntry.phone}
                  onChange={e => setManualEntry({...manualEntry, phone: e.target.value})}
                />
              </div>
              <button className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all">
                Call Now
              </button>
            </form>

            <div className="flex items-center gap-4 py-2">
              <div className="flex-grow border-t border-slate-50"></div>
              <span className="text-[9px] font-bold text-slate-300 uppercase">Batch</span>
              <div className="flex-grow border-t border-slate-50"></div>
            </div>

            <form onSubmit={handleBulkSubmit} className="space-y-3">
              <textarea 
                placeholder="Paste numbers here..."
                className="w-full h-20 bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none focus:border-blue-500 transition-all text-sm font-medium resize-none"
                value={bulkInput}
                onChange={e => setBulkInput(e.target.value)}
              />
              <button className="w-full py-4 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-700 transition-all flex items-center justify-center gap-3">
                <Users className="w-4 h-4" /> Start Mass Call
              </button>
            </form>
          </div>
        </div>

        {/* Saved Leads Quick List */}
        {savedLeads.length > 0 && (
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200">
            <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-6">Call from your leads</h4>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
              {savedLeads.slice(0, 8).map((l: Lead) => (
                <button 
                  key={l.id}
                  onClick={() => { setActiveLead(l); setMode('phone'); }}
                  className="p-4 bg-slate-50 hover:bg-emerald-50 text-slate-600 hover:text-emerald-700 rounded-2xl text-xs font-bold transition-all truncate border border-transparent hover:border-emerald-100 text-left"
                >
                  {l.name}
                </button>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  }

  // --- PRE-CALL / ACTIVE CALL UI ---
  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in fade-in zoom-in-95 duration-500 pb-32">

      {!isCalling && (
        <button 
          onClick={() => { setMode('selection'); setActiveLead(null); setBulkTargets([]); }}
          className="flex items-center gap-2 text-slate-400 hover:text-slate-900 font-black text-[10px] uppercase tracking-widest transition-all px-4"
        >
          <X className="w-4 h-4" /> Change calling method
        </button>
      )}

      <div className={`relative overflow-hidden bg-white border border-slate-200 rounded-[4rem] p-12 shadow-2xl transition-all duration-700 ${isCalling ? 'min-h-[550px]' : 'min-h-[450px]'}`}>

        {isCalling && (
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
            <div className="w-[120%] h-[120%] bg-emerald-500/5 rounded-full animate-pulse blur-3xl" />
            <div className="absolute bottom-10 left-0 right-0 h-32 flex items-end justify-center gap-2 px-10">
              {[...Array(16)].map((_, i) => (
                <div key={i} className="w-3 bg-emerald-400 rounded-full animate-bounce" style={{ 
                  height: `${20 + Math.random() * 80}%`,
                  animationDuration: `${0.6 + Math.random() * 1.2}s`,
                  animationDelay: `${i * 0.1}s`
                }} />
              ))}
            </div>
          </div>
        )}

        <div className="relative z-10 h-full flex flex-col items-center justify-between text-center space-y-12">

