  const playVoice = async (text: string, voiceId: string, isCustom: boolean = false) => {
    if (previewingVoice || isCustomPlaying) return;

    if (isCustom) setIsCustomPlaying(true);
    else setPreviewingVoice(voiceId);

    setError(null);

    try {
      const base64Audio = await synthesizeSpeech(text, voiceId);

      if (!audioCtxRef.current) {
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const audioCtx = audioCtxRef.current;
      const uint8 = base64ToUint8Array(base64Audio);
      const buffer = await decodeAudioData(uint8, audioCtx, 24000, 1);

      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => {
        setPreviewingVoice(null);
        setIsCustomPlaying(false);
      };
      source.start();

    } catch (err: any) {
      console.error("Playback failed", err);
      setError("Voice module link failed. Check your Satellite (API) connection.");
      setPreviewingVoice(null);
      setIsCustomPlaying(false);
