                  {mode === 'web' ? 'Start Bridge' : 'Initiate Dial'}
                </button>
              )}
            </div>
          )}

          {isCalling && (
             <button 
               onClick={handleEndCall}
               className="w-full max-w-sm h-24 bg-red-500 hover:bg-red-600 text-white rounded-[2rem] flex items-center justify-center gap-5 font-black uppercase text-xl tracking-[0.2em] shadow-2xl transition-all active:scale-95"
