        const aValue = sortConfig.key === 'timestamp' ? a.timestamp.getTime() : a[sortConfig.key];
        const bValue = sortConfig.key === 'timestamp' ? b.timestamp.getTime() : b[sortConfig.key];

        if (aValue < bValue) {
          return sortConfig.direction === 'asc' ? -1 : 1;
        }
        if (aValue > bValue) {
          return sortConfig.direction === 'asc' ? 1 : -1;
        }
        return 0;
