import React, { useState, useEffect, useRef } from 'react';
import { 
  Phone, PhoneCall, Mic2, X, Zap, Loader2, 
  PhoneOff, Globe, Signal, User, 
  Plus, Database, MessageSquare,
  Volume2, Mic, Activity, Users, 
  CheckCircle2, Play, MousePointer2,
  Waves, Headset, Info, ChevronDown, Lock,
  Sparkles
} from 'lucide-react';
import { Lead, SwarmTarget } from '../types';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { base64ToUint8Array, decodeAudioData } from '../utils/audioUtils';
import { analyzeCallOutcome } from '../services/gemini';

interface CallInterfaceProps {
  activeLead: Lead | null;
  selectedVoice: string;
  onUpdateLead?: (id: string, updates: Partial<Lead>) => void;
}

const VOICES = [
  { id: 'Rachel', label: 'Rachel (Female)' },
  { id: 'Antoni', label: 'Antoni (Male)' },
  { id: 'Bella', label: 'Bella (Professional)' },
  { id: 'Josh', label: 'Josh (Direct)' },
  { id: 'Arnold', label: 'Arnold (Steady)' }
];

const VOICE_MAP: Record<string, string> = {
  'Rachel': 'Zephyr',
  'Antoni': 'Puck',
  'Bella': 'Kore',
  'Josh': 'Fenrir',
  'Arnold': 'Charon'
};

const CallInterface: React.FC<CallInterfaceProps> = ({ activeLead: initialLead, selectedVoice: initialVoice, onUpdateLead }) => {
  const [activeLead, setActiveLead] = useState<Lead | null>(initialLead);
  const [mode, setMode] = useState<'selection' | 'web' | 'phone' | 'bulk'>('selection');
  const [isCalling, setIsCalling] = useState(false);
  const [callTime, setCallTime] = useState(0);
  const [currentVoice, setCurrentVoice] = useState(initialVoice);
  const [needsApiKey, setNeedsApiKey] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Transcription state
  const [transcript, setTranscript] = useState<string>('');
  const transcriptRef = useRef<string>('');

  // Live API State (AI Conversation)
  const [isLiveActive, setIsLiveActive] = useState(false);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);

  // Inputs
  const [manualEntry, setManualEntry] = useState({ name: '', phone: '' });
  const [bulkInput, setBulkInput] = useState('');
  const [bulkTargets, setBulkTargets] = useState<SwarmTarget[]>([]);

  useEffect(() => {
    if (initialLead) {
      setActiveLead(initialLead);
      setMode('phone');
    }
  }, [initialLead]);

  useEffect(() => {
    let interval: number;
    if (isCalling) {
      interval = window.setInterval(() => {
        setCallTime(prev => prev + 1);
      }, 1000);
    }
    return () => {
      clearInterval(interval);
      if (isLiveActive) stopLiveSession();
    };
  }, [isCalling, isLiveActive]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const checkApiKeyPermissions = async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setNeedsApiKey(true);
        return false;
      }
    }
    return true;
  };

  const handleOpenKeySelector = async () => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      await window.aistudio.openSelectKey();
      setNeedsApiKey(false);
      handleStartCall();
    }
  };

  const startLiveSession = async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    setIsLiveActive(true);
    setTranscript('');
    transcriptRef.current = '';

    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const outCtx = audioCtxRef.current;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const instructions = localStorage.getItem('nexus_ai_instructions') || "You are a friendly AI assistant. Talk naturally.";
      const mappedVoice = VOICE_MAP[currentVoice] || 'Zephyr';

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: mappedVoice } }
          },
          systemInstruction: instructions,
          outputAudioTranscription: {},
          inputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            const source = inCtx.createMediaStreamSource(stream);
            const processor = inCtx.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const base64 = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));
              sessionPromise.then((session) => {
                session.sendRealtimeInput({ 
                  media: { data: base64, mimeType: 'audio/pcm;rate=16000' } 
                });
              });
            };
            source.connect(processor);
            processor.connect(inCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Audio
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const uint8 = base64ToUint8Array(audioData);
              const buffer = await decodeAudioData(uint8, outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            // Handle Transcriptions
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              transcriptRef.current += `\nAI: ${text}`;
              setTranscript(prev => prev + text);
            } else if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              transcriptRef.current += `\nUSER: ${text}`;
            }
          },
          onclose: () => {
            setIsLiveActive(false);
            setIsCalling(false);
          },
          onerror: (err: any) => {
            console.error("AI Bridge Error", err);
            if (err?.message?.includes('permission') || err?.message?.includes('403')) {
              setNeedsApiKey(true);
            }
            setIsLiveActive(false);
            setIsCalling(false);
          }
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e: any) {
      console.error("Connection failed", e);
      if (e?.message?.includes('permission')) setNeedsApiKey(true);
      setIsLiveActive(false);
      setIsCalling(false);
    }
  };

  const stopLiveSession = async () => {
    sessionRef.current?.close();
    sourcesRef.current.forEach(s => {
      try { s.stop(); } catch(e) {}
    });
    sourcesRef.current.clear();
    setIsLiveActive(false);

    // Perform post-call analysis
    if (activeLead && transcriptRef.current && onUpdateLead) {
      setIsAnalyzing(true);
      try {
        const result = await analyzeCallOutcome(activeLead, transcriptRef.current);
        onUpdateLead(activeLead.id, {
          ...result,
          summary: transcriptRef.current,
          status: 'Contacted'
        });
      } catch (err) {
        console.error("Post-call analysis failed", err);
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  const handleStartCall = async () => {
    if (mode === 'web') {
      const hasPermission = await checkApiKeyPermissions();
      if (!hasPermission) return;
      setIsCalling(true);
      setCallTime(0);
      startLiveSession();
    } else {
      setIsCalling(true);
      setCallTime(0);
      if (mode === 'bulk') executeBulk();
    }
  };

  const executeBulk = async () => {
    const targets = bulkTargets.map(t => ({ ...t, status: 'Pending' as const }));
    setBulkTargets(targets);
    for (let i = 0; i < targets.length; i++) {
      if (!isCalling) break;
      const updated = [...targets];
      updated[i].status = 'Calling';
      setBulkTargets([...updated]);
      await new Promise(r => setTimeout(r, 3000));
      updated[i].status = Math.random() > 0.1 ? 'Completed' : 'Failed';
      setBulkTargets([...updated]);
    }
    setIsCalling(false);
  };

  const handleEndCall = () => {
    setIsCalling(false);
    if (mode === 'web') stopLiveSession();
  };

  const handleManualCall = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualEntry.name || !manualEntry.phone) return;
    setActiveLead({
      id: crypto.randomUUID(),
      name: manualEntry.name,
      phone: manualEntry.phone,
      address: 'Direct Entry',
      type: 'Phone Call',
      status: 'New'
    });
    setMode('phone');
  };

  const handleBulkSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numbers = bulkInput.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 0);
    if (numbers.length === 0) return;
    const targets: SwarmTarget[] = numbers.map((n, idx) => ({
      id: `bulk-${idx}`,
      name: `Target ${idx + 1}`,
      phone: n,
      status: 'Pending'
    }));
    setBulkTargets(targets);
    setMode('bulk');
    setActiveLead(null);
  };

  if (mode === 'selection') {
    const savedLeads = JSON.parse(localStorage.getItem('nexus_leads') || '[]');
    return (
      <div className="max-w-4xl mx-auto space-y-10 pb-20 animate-in fade-in duration-500">
        <div className="text-center space-y-3">
          <h1 className="text-4xl font-extrabold text-slate-900 tracking-tighter uppercase">Call Center</h1>
          <p className="text-slate-500 font-medium">Select your preferred AI audio bridge.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="flex flex-col space-y-4">
            <button 
              onClick={() => {
                setMode('web');
                setActiveLead({ id: 'ai', name: 'AI Partner', address: 'Local', type: 'Web Call', status: 'New' });
              }}
              className="p-10 bg-white border-2 border-slate-100 rounded-[2.5rem] hover:border-emerald-500 hover:shadow-xl transition-all flex flex-col items-center text-center space-y-6 group active:scale-95"
            >
              <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-3xl flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all">
                <Mic2 className="w-10 h-10" />
              </div>
              <div>
                <h3 className="text-2xl font-bold text-slate-900">AI Bridge Call</h3>
                <p className="text-sm text-slate-500 mt-2">Real-time voice conversation directly in your browser. Powered by Neural Vocal Profiles.</p>
              </div>
              <div className="w-full h-px bg-slate-50"></div>
              <div className="text-[10px] font-black uppercase text-emerald-500 tracking-[0.2em]">Neural Audio Uplink</div>
            </button>
          </div>

          <div className="p-10 bg-white border-2 border-slate-100 rounded-[2.5rem] space-y-6 shadow-sm">
            <div className="flex items-center gap-4">
