                   <p className="text-sm font-bold text-slate-400 animate-in slide-in-from-bottom-2 italic">
                     {transcript || 'Monitoring audio uplink...'}
                   </p>
                 </div>
               </div>
            )}
          </div>

          {!isCalling && (
            <div className="w-full max-w-sm space-y-6">
              {mode === 'web' && (
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <Volume2 className="w-3 h-3" /> Selected Voice Profile
                  </label>
                  <div className="relative">
                    <select 
                      value={currentVoice}
                      onChange={(e) => setCurrentVoice(e.target.value)}
                      className="w-full bg-slate-50 border-2 border-slate-100 p-4 rounded-2xl font-bold text-sm text-slate-700 outline-none focus:border-emerald-500 appearance-none transition-all pr-12"
                    >
                      {VOICES.map(v => <option key={v.id} value={v.id}>{v.label}</option>)}
                    </select>
                    <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 pointer-events-none" />
                  </div>
                </div>
              )}

              {needsApiKey ? (
                <div className="p-6 bg-amber-50 rounded-3xl border border-amber-200 text-left space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex items-center gap-2 text-amber-700">
                    <Lock className="w-5 h-5" />
                    <span className="text-sm font-black uppercase tracking-tight">Permission Required</span>
                  </div>
                  <p className="text-xs text-amber-800 font-bold leading-relaxed">
                    The Live AI Bridge requires an authorized API Key from a paid Google Cloud project.
                  </p>
                  <button 
                    onClick={handleOpenKeySelector}
                    className="w-full py-4 bg-amber-500 text-white rounded-xl font-black uppercase text-[10px] tracking-widest shadow-lg hover:bg-amber-600 transition-all"
                  >
                    Authorize API Key
                  </button>
                </div>
              ) : (
                <button 
                  onClick={handleStartCall}
                  className={`w-full h-24 rounded-[2rem] flex items-center justify-center gap-5 font-black uppercase text-xl tracking-[0.2em] shadow-2xl transition-all active:scale-95 text-white ${mode === 'web' ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
                >
                  {mode === 'web' ? <Mic2 className="w-8 h-8" /> : <Play className="w-8 h-8" />}
                  {mode === 'web' ? 'Start Session' : 'Initiate Dial'}
                </button>
              )}
            </div>
          )}

          {isCalling && (
             <button 
               onClick={handleEndCall}
               className="w-full max-w-sm h-24 bg-red-500 hover:bg-red-600 text-white rounded-[2rem] flex items-center justify-center gap-5 font-black uppercase text-xl tracking-[0.2em] shadow-2xl transition-all active:scale-95"
             >
               <PhoneOff className="w-8 h-8" /> End Call
             </button>
          )}

          {isAnalyzing && (
            <div className="flex flex-col items-center gap-3 text-emerald-600 animate-pulse">
              <Sparkles className="w-6 h-6" />
              <span className="text-[10px] font-black uppercase tracking-widest">Neural Analysis in Progress...</span>
            </div>
          )}

          {!isCalling && !isAnalyzing && (
            <div className="flex justify-center gap-8">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-300 uppercase tracking-widest">
                <Globe className="w-4 h-4" /> Ready
              </div>
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-300 uppercase tracking-widest">
                <Signal className="w-4 h-4" /> Stable
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

