}

type SortKey = 'timestamp' | 'duration' | 'status';
interface SortConfig {
  key: SortKey;
  direction: 'asc' | 'desc';
}

const AnalyticsDashboard: React.FC<AnalyticsDashboardProps> = ({ leads, onCallLead }) => {
  const [dossier, setDossier] = useState<string | null>(null);
