      timestamp: new Date('2024-09-03T07:07:00'),
      duration: 420,
      status: 'Connected',
      type: 'Incoming'
    },
    {
      id: '2',
      targetName: 'Nairobi Primary',
      targetPhone: '706.194.5420',
      timestamp: new Date('2024-09-03T07:46:00'),
      duration: 3,
      status: 'Rejected',
      type: 'Outgoing'
    },
    {
      id: '3',
      targetName: 'Westlands Academy',
      targetPhone: '706.194.5420',
      timestamp: new Date('2024-09-03T07:51:00'),
      duration: 3,
      status: 'Connected',
