export async function synthesizeElevenLabs(text: string, voiceId: string, apiKey: string): Promise<string> {
  // Map our internal names to ElevenLabs voice IDs (standard defaults)
  const VOICE_ID_MAP: Record<string, string> = {
    'Rachel': '21m00Tcm4TlvDq8ikWAM',
    'Antoni': 'ErXwVqcDbiBe7sD9K3Ky',
    'Bella': 'EXAVITQu4vr4xnSDxMaL',
    'Josh': 'TxGEqnHW47o3yi70j373',
    'Arnold': 'VR6AewrYgNE7noTNNo9G'
  };

  const selectedVoiceId = VOICE_ID_MAP[voiceId] || VOICE_ID_MAP['Rachel'];

  const response = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${selectedVoiceId}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'xi-api-key': apiKey,
    },
    body: JSON.stringify({
      text: text,
      model_id: 'eleven_monolingual_v1',
      voice_settings: {
        stability: 0.5,
        similarity_boost: 0.75,
      },
    }),
  });

  if (!response.ok) {
    throw new Error(`ElevenLabs API Error: ${response.statusText}`);
  }

  const arrayBuffer = await response.arrayBuffer();
  const base64 = btoa(
    new Uint8Array(arrayBuffer).reduce((data, byte) => data + String.fromCharCode(byte), '')
  );
  return base64;
}

import { GoogleGenAI, Modality, Type } from "@google/genai";
import { Lead } from "../types";
import { synthesizeElevenLabs } from "./elevenlabs";

/**
 * Maps ElevenLabs style names to Gemini Prebuilt voices
 */
const VOICE_MAP: Record<string, string> = {
  'Rachel': 'Zephyr',
  'Antoni': 'Puck',
  'Bella': 'Kore',
  'Josh': 'Fenrir',
  'Arnold': 'Charon'
};

/**
 * Parses the Markdown table response from Gemini.
 */
const parseLeadsFromMarkdown = (text: string, groundingChunks: any[] = []): Lead[] => {
  const lines = text.split('\n');
  const leads: Lead[] = [];
  let isTable = false;

  for (const line of lines) {
    if (line.includes('|---')) {
      isTable = true;
      continue;
    }
    if (isTable && line.trim().startsWith('|')) {
      const parts = line.split('|').map(p => p.trim()).filter(p => p !== '');
      if (parts.length >= 3) {
        const name = parts[0];
        const address = parts[1];
        const phone = parts.length > 3 ? parts[3] : undefined;
        const email = parts.length > 4 ? parts[4] : undefined;
        const type = parts[2];

        const chunk = groundingChunks.find((c: any) => 
          c.web?.title?.toLowerCase().includes(name.toLowerCase()) || 
          c.maps?.title?.toLowerCase().includes(name.toLowerCase())
        );

        let uri = undefined;
        if (chunk?.web?.uri) uri = chunk.web.uri;
        if (chunk?.maps?.uri) uri = chunk.maps.uri;

        leads.push({
          id: crypto.randomUUID(),
          name,
          address,
          type,
          phone: phone !== 'N/A' ? phone : undefined,
          email: email !== 'N/A' ? email : undefined,
          status: 'New',
          googleMapsUri: uri
        });
      }
    }
  }
  return leads;
};

export const searchLeadsWithGemini = async (
  query: string, 
  location: string
): Promise<{ leads: Lead[], rawText: string }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    Find exactly 10 high-quality ${query} in "${location}".
    Output the results strictly as a Markdown table with these columns:
    | Name | Full Address | Category | Phone | Email |
    If phone or email is unknown, use "N/A".
  `;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: { tools: [{ googleMaps: {} }], temperature: 0.1 },
    });
    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const leads = parseLeadsFromMarkdown(text, groundingChunks);
    return { leads, rawText: text };
  } catch (error) {
    console.error("Gemini Search Error:", error);
    throw error;
  }
};

export const enrichLeadsWithGemini = async (leads: Lead[]): Promise<Lead[]> => {
  if (leads.length === 0) return [];
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const enrichedLeads: Lead[] = [...leads];
  const batchSize = 5;
  const promises = [];

  for (let i = 0; i < leads.length; i += batchSize) {
    const batch = leads.slice(i, i + batchSize);
    const prompt = `Find official contact info for: ${batch.map(l => l.name).join(', ')}. Format: NAME: X, PHONE: Y, EMAIL: Z. Use Search.`;
    promises.push(ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: prompt,
      config: { tools: [{ googleSearch: {} }], temperature: 0 },
    }));
  }

  try {
    const results = await Promise.all(promises);
    results.forEach(response => {
      const text = response.text || "";
      const chunks = text.split('\n');
      chunks.forEach(chunk => {
        const nameMatch = chunk.match(/NAME:\s*(.+)/i);
        if (nameMatch) {
          const nameValue = nameMatch[1].trim().toLowerCase();
          const phoneMatch = chunk.match(/PHONE:\s*(.+)/i);
          const emailMatch = chunk.match(/EMAIL:\s*(.+)/i);
          const idx = enrichedLeads.findIndex(l => l.name.toLowerCase().includes(nameValue) || nameValue.includes(l.name.toLowerCase()));
          if (idx !== -1) {
            enrichedLeads[idx] = {
              ...enrichedLeads[idx],
              phone: phoneMatch ? phoneMatch[1].trim() : enrichedLeads[idx].phone,
              email: emailMatch ? emailMatch[1].trim() : enrichedLeads[idx].email,
            };
          }
        }
      });
    });
  } catch (err) { console.error(err); }
  return enrichedLeads;
};

export const generateStrategicDossier = async (leads: Lead[]): Promise<string> => {
