          </div>

          <div className="space-y-4">
            <h1 className="text-5xl md:text-7xl font-black text-slate-950 tracking-tighter uppercase leading-none">
              Scout <span className="text-emerald-500">Protocol</span>
            </h1>
            <p className="max-w-xl text-lg font-bold text-slate-400 leading-tight">
