            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-4">
             <BriefingStep number="01" label="Define Sector" sub="Target schools, tech, or real estate" />
             <BriefingStep number="02" label="Set Region" sub="Deploy search to specific coordinates" />
             <BriefingStep number="03" label="Launch Scan" sub="Satellite ingest of contact signals" />
          </div>
        </div>
      </div>

      {/* QUICK ACTION BAR */}
      <div className="flex flex-col md:flex-row gap-4">
        <div className="flex-1 bg-emerald-950 p-6 rounded-[2rem] flex items-center justify-between shadow-2xl group cursor-pointer hover:bg-black transition-all" onClick={handleScan}>
           <div className="flex items-center gap-5">
             <div className="w-14 h-14 bg-emerald-500/20 text-emerald-400 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
               <Rocket className="w-8 h-8 fill-current" />
             </div>
             <div>
               <h3 className="text-white font-black uppercase text-xs tracking-[0.2em]">Deploy Mass Search</h3>
