import React, { useState } from 'react';
import { Search, MapPin, Loader2, Zap, Info, Target, Download, Trash2, Mail, Phone, FileDown } from 'lucide-react';
import { Lead } from '../types';
import { searchLeadsWithGemini, enrichLeadsWithGemini } from '../services/gemini';

interface LeadFinderProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  onCallLead: (lead: Lead) => void;
}

const LeadFinder: React.FC<LeadFinderProps> = ({ leads, setLeads, onCallLead }) => {
  const [query, setQuery] = useState('Schools'); // Default set to Schools as requested
  const [location, setLocation] = useState('Nairobi, Kenya');
  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<Lead[]>([]);

  const handleScan = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!query || !location) return;
    setLoading(true);
    setError(null);
    setResults([]);
    try {
      const { leads: fetched } = await searchLeadsWithGemini(query, location);
      if (fetched.length > 0) {
        setResults(fetched);
      } else {
        setError("No new leads found for this location.");
      }
    } catch (err) {
      setError("Search failed. Please check your API configuration in settings.");
    } finally {
      setLoading(false);
    }
  };

  const handleIngest = async (lead: Lead) => {
    try {
      const enriched = await enrichLeadsWithGemini([lead]);
      setLeads(prev => [...enriched, ...prev]);
      setResults(prev => prev.filter(r => r.id !== lead.id));
    } catch (e) {
      setLeads(prev => [lead, ...prev]);
      setResults(prev => prev.filter(r => r.id !== lead.id));
    }
  };

  const downloadCSV = () => {
    const dataToExport = results.length > 0 ? results : leads;
    if (dataToExport.length === 0) return;

    setExporting(true);

    const headers = ['Name', 'Type', 'Address', 'Phone', 'Email', 'Maps Link'];
    const csvContent = [
      headers.join(','),
      ...dataToExport.map(l => [
        `"${l.name.replace(/"/g, '""')}"`,
        `"${l.type.replace(/"/g, '""')}"`,
        `"${l.address.replace(/"/g, '""')}"`,
        `"${(l.phone || 'N/A').replace(/"/g, '""')}"`,
        `"${(l.email || 'N/A').replace(/"/g, '""')}"`,
        `"${(l.googleMapsUri || 'N/A').replace(/"/g, '""')}"`
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `Nexus_Leads_${query.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => setExporting(false), 1000);
  };

  const activeData = results.length > 0 ? results : leads;

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-500">

      {/* HEADER */}
      <div className="space-y-2">
        <h1 className="text-4xl font-black text-slate-950 tracking-tight uppercase">
          Lead <span className="text-emerald-600">Scout</span>
        </h1>
        <p className="text-sm font-medium text-slate-500">
          Search and collect business leads directly from Google Maps.
        </p>
      </div>

      {/* SEARCH INTERFACE */}
      <div className="bg-white rounded-3xl border border-slate-200 p-6 md:p-8 shadow-sm space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Business Type</label>
            <div className="relative">
              <input 
                type="text" 
                value={query} 
                onChange={e => setQuery(e.target.value)}
                placeholder="e.g. Schools"
                className="w-full h-14 bg-slate-50 border border-slate-200 rounded-xl px-12 font-bold text-slate-800 focus:border-emerald-500 focus:bg-white outline-none transition-all"
              />
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Location</label>
            <div className="relative">
              <input 
                type="text" 
                value={location} 
                onChange={e => setLocation(e.target.value)}
                placeholder="e.g. Westlands, Nairobi"
                className="w-full h-14 bg-slate-50 border border-slate-200 rounded-xl px-12 font-bold text-slate-800 focus:border-emerald-500 focus:bg-white outline-none transition-all"
              />
              <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
            </div>
          </div>
        </div>

        <button 
          onClick={() => handleScan()}
          disabled={loading}
          className="w-full h-14 bg-emerald-600 text-white rounded-xl font-black uppercase text-sm tracking-widest shadow-lg hover:bg-emerald-700 transition-all active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-3"
        >
          {loading ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              Searching...
            </>
          ) : (
            <>
              <Zap className="w-5 h-5 fill-current" />
              Find Leads
            </>
          )}
        </button>

        {error && (
          <div className="p-4 bg-red-50 rounded-xl border border-red-100 flex items-center gap-3">
            <Info className="w-5 h-5 text-red-500" />
            <p className="text-xs font-bold text-red-600 uppercase">{error}</p>
          </div>
        )}
      </div>

      {/* RESULTS GRID */}
      <div className="space-y-6">
        <div className="flex items-center justify-between px-2">
          <div className="flex items-center gap-3">
             <Target className="w-5 h-5 text-emerald-600" />
             <h3 className="text-xl font-black text-slate-950 uppercase tracking-tight">
               {results.length > 0 ? 'Search Results' : 'Saved Intelligence'}
             </h3>
          </div>
          <div className="flex gap-3">
            {activeData.length > 0 && (
              <button 
                onClick={downloadCSV}
                disabled={exporting}
                className="flex items-center gap-2 px-4 py-1.5 bg-white border border-slate-200 rounded-xl text-[10px] font-black text-slate-600 uppercase tracking-widest hover:border-emerald-500 hover:text-emerald-600 transition-all shadow-sm disabled:opacity-50"
              >
                {exporting ? <Loader2 className="w-3 h-3 animate-spin" /> : <FileDown className="w-3 h-3" />}
                Export CSV
              </button>
            )}
            <div className="px-3 py-1.5 bg-slate-100 rounded-xl text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center">
              {activeData.length} Records
            </div>
            {leads.length > 0 && results.length === 0 && (
               <button className="p-2 text-slate-400 hover:text-red-500 transition-colors" onClick={() => setLeads([])} title="Clear Saved Leads">
                 <Trash2 className="w-5 h-5" />
               </button>
            )}
          </div>
        </div>

        <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
          <div className="divide-y divide-slate-100">
            {activeData.map((lead) => (
              <div key={lead.id} className="group p-6 space-y-4 hover:bg-slate-50/50 transition-all">
                <div className="flex items-start gap-6">
                  <div className="w-14 h-14 bg-white border border-slate-200 rounded-2xl flex items-center justify-center font-black text-xl text-slate-900 shadow-sm group-hover:border-emerald-200 transition-all">
                    {lead.name.charAt(0)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <h4 className="text-lg font-black text-slate-950 uppercase tracking-tight truncate">{lead.name}</h4>
                      <div className="px-2 py-0.5 bg-slate-100 rounded text-[8px] font-black text-slate-500 uppercase tracking-widest">{lead.type}</div>
                    </div>
                    <p className="text-xs font-bold text-slate-400 mt-1 truncate">{lead.address}</p>

                    <div className="mt-4 flex flex-wrap gap-3">
                      {lead.phone && (
                        <div className="flex items-center gap-1.5 text-[9px] font-black text-emerald-600 uppercase">
                          <Phone className="w-3 h-3" /> {lead.phone}
                        </div>
                      )}
                      {lead.email && (
                        <div className="flex items-center gap-1.5 text-[9px] font-black text-blue-500 uppercase">
                          <Mail className="w-3 h-3" /> {lead.email}
                        </div>
                      )}
                    </div>
                  </div>

                  <div className="flex flex-col gap-2">
                    <button 
                      onClick={() => results.length > 0 ? handleIngest(lead) : onCallLead(lead)}
                      className="h-10 px-6 bg-slate-900 text-white rounded-xl hover:bg-black transition-all shadow-md flex items-center gap-2 font-black uppercase text-[10px] tracking-widest active:scale-95"
                    >
                      <Zap className="w-4 h-4 text-emerald-400 fill-current" />
                      {results.length > 0 ? 'Save' : 'Call'}
                    </button>
                    {lead.googleMapsUri && (
                      <a 
                        href={lead.googleMapsUri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="text-[9px] font-black text-slate-400 hover:text-emerald-600 text-center uppercase tracking-widest"
                      >
                        Map Link
                      </a>
                    )}
                  </div>
                </div>
              </div>
            ))}
            {activeData.length === 0 && (
              <div className="p-20 text-center space-y-4">
                <div className="w-16 h-16 bg-slate-50 rounded-2xl flex items-center justify-center mx-auto">
                   <Search className="w-8 h-8 text-slate-200" />
                </div>
                <div className="space-y-1">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">No leads found</p>
                  <p className="text-[9px] font-bold text-slate-300 uppercase tracking-widest max-w-[200px] mx-auto">Enter a business type and location to start scouting.</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default LeadFinder;

