export const synthesizeSpeech = async (text: string, voiceName: string): Promise<string> => {
  if (!text || text.trim().length === 0) {
    throw new Error("No text provided for synthesis.");
  }

  const savedKeys = localStorage.getItem('nexus_api_keys');
  const apiKeys = savedKeys ? JSON.parse(savedKeys) : {};

  // PRIMARY: ElevenLabs
  if (apiKeys.elevenlabs && apiKeys.elevenlabs.trim() !== '') {
    try {
      return await synthesizeElevenLabs(text, voiceName, apiKeys.elevenlabs);
    } catch (e) {
      console.warn("ElevenLabs bridge failed", e);
      // Only fall back if ElevenLabs fails
    }
  }

  // SECONDARY: Gemini TTS
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const mappedVoice = VOICE_MAP[voiceName] || 'Zephyr';

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Say: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: mappedVoice },
        },
      },
    },
  });

  const parts = response.candidates?.[0]?.content?.parts || [];
  const audioPart = parts.find(p => p.inlineData && p.inlineData.data);
  const base64Audio = audioPart?.inlineData?.data;

  if (!base64Audio) {
    throw new Error("Speech synthesis failed: No audio data available.");
  }

  return base64Audio;
};

