            <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-3xl flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all">
              <Mic2 className="w-10 h-10" />
            </div>
            <div>
              <h3 className="text-2xl font-bold text-slate-900">AI Bridge Call</h3>
              <p className="text-sm text-slate-500 mt-2">Real-time voice conversation. Uses your ElevenLabs or Gemini configuration.</p>
