      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const instructions = localStorage.getItem('nexus_ai_instructions') || "You are a professional outreach agent. Your goal is to build rapport and confirm contact details.";
      const mappedVoice = VOICE_MAP[currentVoice] || 'Zephyr';

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: mappedVoice } }
          },
          systemInstruction: instructions,
          outputAudioTranscription: {},
          inputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            const source = inCtx.createMediaStreamSource(stream);
            const processor = inCtx.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            source.connect(processor);
            processor.connect(inCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const uint8 = base64ToUint8Array(audioData);
              const buffer = await decodeAudioData(uint8, outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              transcriptRef.current += `\nAI: ${text}`;
              setTranscript(prev => prev + text);
            } else if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              transcriptRef.current += `\nUSER: ${text}`;
            }
          },
          onclose: () => {
            setIsLiveActive(false);
            setIsCalling(false);
          },
          onerror: (err: any) => {
            console.error("AI Bridge Error", err);
            setErrorMessage("Connection interrupted. Check your API key or network.");
            setIsLiveActive(false);
            setIsCalling(false);
          }
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e: any) {
      console.error("Connection failed", e);
      setErrorMessage(e.message || "Failed to establish neural bridge.");
      setIsLiveActive(false);
      setIsCalling(false);
    }
  };

  const stopLiveSession = async () => {
    sessionRef.current?.close();
    sourcesRef.current.forEach(s => {
      try { s.stop(); } catch(e) {}
    });
    sourcesRef.current.clear();
    setIsLiveActive(false);

    if (activeLead && transcriptRef.current && onUpdateLead) {
      setIsAnalyzing(true);
      try {
        const result = await analyzeCallOutcome(activeLead, transcriptRef.current);
        onUpdateLead(activeLead.id, {
          ...result,
          summary: transcriptRef.current,
          status: 'Contacted'
        });
      } catch (err) {
        console.error("Post-call analysis failed", err);
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  const handleStartCall = async () => {
    setIsCalling(true);
    setCallTime(0);
    if (mode === 'web') {
      startLiveSession();
    } else if (mode === 'bulk') {
      executeBulk();
    }
  };

  const handleEndCall = () => {
    setIsCalling(false);
    if (mode === 'web') stopLiveSession();
  };

  const handleManualCall = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualEntry.name || !manualEntry.phone) return;
    setActiveLead({
      id: crypto.randomUUID(),
      name: manualEntry.name,
      phone: manualEntry.phone,
      address: 'Direct Entry',
      type: 'Phone Call',
      status: 'New'
    });
    setMode('phone');
  };

  const handleBulkSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numbers = bulkInput.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 0);
    if (numbers.length === 0) return;
    const targets: SwarmTarget[] = numbers.map((n, idx) => ({
      id: `bulk-${idx}`,
      name: `Target ${idx + 1}`,
      phone: n,
      status: 'Pending'
    }));
    setBulkTargets(targets);
    setMode('bulk');
    setActiveLead(null);
  };

  const executeBulk = async () => {
    const targets = bulkTargets.map(t => ({ ...t, status: 'Pending' as const }));
    setBulkTargets(targets);
    for (let i = 0; i < targets.length; i++) {
      if (!isCalling) break;
      const updated = [...targets];
      updated[i].status = 'Calling';
      setBulkTargets([...updated]);
      await new Promise(r => setTimeout(r, 3000));
      updated[i].status = Math.random() > 0.1 ? 'Completed' : 'Failed';
      setBulkTargets([...updated]);
    }
    setIsCalling(false);
  };

  if (mode === 'selection') {
    return (
      <div className="max-w-4xl mx-auto space-y-10 pb-20 animate-in fade-in duration-500">
        <div className="text-center space-y-3">
          <h1 className="text-4xl font-extrabold text-slate-900 tracking-tighter uppercase">Call Center</h1>
          <p className="text-slate-500 font-medium">Initiate your outreach protocol.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <button 
            onClick={() => {
              setMode('web');
              setActiveLead({ id: 'ai', name: 'AI Partner', address: 'Local', type: 'Web Call', status: 'New' });
            }}
            className="p-10 bg-white border-2 border-slate-100 rounded-[2.5rem] hover:border-emerald-500 hover:shadow-xl transition-all flex flex-col items-center text-center space-y-6 group active:scale-95"
          >
            <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-3xl flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all">
              <Mic2 className="w-10 h-10" />
            </div>
            <div>
              <h3 className="text-2xl font-bold text-slate-900">AI Bridge Call</h3>
              <p className="text-sm text-slate-500 mt-2">Real-time voice conversation. Powered by Gemini & ElevenLabs infrastructure.</p>
            </div>
            <div className="w-full h-px bg-slate-50"></div>
            <div className="text-[10px] font-black uppercase text-emerald-500 tracking-[0.2em]">Neural Uplink Ready</div>
          </button>

          <div className="p-10 bg-white border-2 border-slate-100 rounded-[2.5rem] space-y-6 shadow-sm">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center">
                <PhoneCall className="w-6 h-6" />
              </div>
              <h3 className="text-xl font-bold text-slate-900">Classic Dial</h3>
            </div>

            <form onSubmit={handleManualCall} className="space-y-3">
              <div className="flex gap-2">
                <input placeholder="Name" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none text-sm font-bold" value={manualEntry.name} onChange={e => setManualEntry({...manualEntry, name: e.target.value})} />
                <input placeholder="Number" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none text-sm font-bold" value={manualEntry.phone} onChange={e => setManualEntry({...manualEntry, phone: e.target.value})} />
              </div>
              <button className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all">Dial Coordinate</button>
            </form>

            <form onSubmit={handleBulkSubmit} className="space-y-3 pt-4 border-t border-slate-50">
              <textarea placeholder="Batch numbers..." className="w-full h-20 bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none text-sm font-medium resize-none" value={bulkInput} onChange={e => setBulkInput(e.target.value)} />
              <button className="w-full py-4 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-700 transition-all flex items-center justify-center gap-3"><Users className="w-4 h-4" /> Start Mass Call</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in fade-in zoom-in-95 duration-500 pb-32">
      {!isCalling && (
        <button onClick={() => { setMode('selection'); setActiveLead(null); setBulkTargets([]); }} className="flex items-center gap-2 text-slate-400 hover:text-slate-900 font-black text-[10px] uppercase tracking-widest transition-all px-4">
          <X className="w-4 h-4" /> Return to Menu
        </button>
      )}

      {errorMessage && (
        <div className="mx-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-4 text-red-600">
           <AlertCircle className="w-5 h-5 shrink-0" />
           <p className="text-xs font-black uppercase tracking-tight">{errorMessage}</p>
        </div>
      )}

      <div className={`relative overflow-hidden bg-white border border-slate-200 rounded-[4rem] p-12 shadow-2xl transition-all duration-700 ${isCalling ? 'min-h-[500px]' : 'min-h-[400px]'}`}>
        {isCalling && (
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
            <div className="w-[120%] h-[120%] bg-emerald-500/5 rounded-full animate-pulse blur-3xl" />
