                {mode === 'web' ? 'Vocal Bridge Active' : 'Cellular Connection'}
              </span>
            </div>

            {isCalling && (
               <div className="space-y-4">
                 <p className="text-7xl font-black tabular-nums text-slate-900 tracking-tighter">{formatTime(callTime)}</p>
