          {!isCalling && (
            <div className="w-full max-w-sm space-y-6">
              {mode === 'web' && (
                <div className="relative">
                  <select value={currentVoice} onChange={(e) => setCurrentVoice(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 p-4 rounded-2xl font-bold text-sm text-slate-700 outline-none pr-12 appearance-none">
                    {VOICES.map(v => <option key={v.id} value={v.id}>{v.label}</option>)}
                  </select>
                  <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 pointer-events-none" />
