import React, { useState, useEffect, useRef } from 'react';
import { 
  Phone, PhoneCall, Mic2, X, Zap, Loader2, 
  PhoneOff, Globe, Signal, User, 
  Plus, Database, MessageSquare,
  Volume2, Mic, Activity, Users, 
  CheckCircle2, Play, MousePointer2,
  Waves, Headset, Info, ChevronDown, Lock,
  Sparkles, AlertCircle
} from 'lucide-react';
import { Lead, SwarmTarget } from '../types';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { base64ToUint8Array, decodeAudioData, createPcmBlob } from '../utils/audioUtils';
import { analyzeCallOutcome } from '../services/gemini';

interface CallInterfaceProps {
  activeLead: Lead | null;
  selectedVoice: string;
  onUpdateLead?: (id: string, updates: Partial<Lead>) => void;
}

const VOICES = [
  { id: 'Rachel', label: 'Rachel (Vibrant)' },
  { id: 'Antoni', label: 'Antoni (Warm)' },
  { id: 'Bella', label: 'Bella (Steady)' },
  { id: 'Josh', label: 'Josh (Clear)' },
  { id: 'Arnold', label: 'Arnold (Deep)' }
];

const VOICE_MAP: Record<string, string> = {
  'Rachel': 'Zephyr',
  'Antoni': 'Puck',
  'Bella': 'Kore',
  'Josh': 'Fenrir',
  'Arnold': 'Charon'
};

const CallInterface: React.FC<CallInterfaceProps> = ({ activeLead: initialLead, selectedVoice: initialVoice, onUpdateLead }) => {
  const [activeLead, setActiveLead] = useState<Lead | null>(initialLead);
  const [mode, setMode] = useState<'selection' | 'web' | 'phone' | 'bulk'>('selection');
  const [isCalling, setIsCalling] = useState(false);
  const [callTime, setCallTime] = useState(0);
  const [currentVoice, setCurrentVoice] = useState(initialVoice);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const [transcript, setTranscript] = useState<string>('');
  const transcriptRef = useRef<string>('');

  const [isLiveActive, setIsLiveActive] = useState(false);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);

  const [manualEntry, setManualEntry] = useState({ name: '', phone: '' });
  const [bulkInput, setBulkInput] = useState('');
  const [bulkTargets, setBulkTargets] = useState<SwarmTarget[]>([]);

  useEffect(() => {
    if (initialLead) {
      setActiveLead(initialLead);
      setMode('phone');
    }
  }, [initialLead]);

  useEffect(() => {
    let interval: number;
    if (isCalling) {
      interval = window.setInterval(() => {
        setCallTime(prev => prev + 1);
      }, 1000);
    }
    return () => {
      clearInterval(interval);
      if (isLiveActive) stopLiveSession();
    };
  }, [isCalling, isLiveActive]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const startLiveSession = async () => {
    setErrorMessage(null);
    setTranscript('');
    transcriptRef.current = '';

    // Check for Paid API Key as required for Live models
    const hasKey = await (window as any).aistudio?.hasSelectedApiKey();
    if (!hasKey) {
      setErrorMessage("Paid API Key selection required for Gemini Live features.");
      await (window as any).aistudio?.openSelectKey();
      // Proceeding after triggering dialog as per race condition handling rules
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const outCtx = audioCtxRef.current;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const instructions = localStorage.getItem('nexus_ai_instructions') || "You are a professional AI outreach assistant. Speak naturally, be helpful, and try to gather business needs.";
      const mappedVoice = VOICE_MAP[currentVoice] || 'Zephyr';

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: mappedVoice } }
          },
          systemInstruction: instructions,
          outputAudioTranscription: {},
          inputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            setIsLiveActive(true);
            setIsCalling(true);
            const source = inCtx.createMediaStreamSource(stream);
            const processor = inCtx.createScriptProcessor(4096, 1, 1);
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            source.connect(processor);
            processor.connect(inCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const uint8 = base64ToUint8Array(audioData);
              const buffer = await decodeAudioData(uint8, outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              transcriptRef.current += text;
              setTranscript(prev => prev + text);
            } else if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              transcriptRef.current += ` [User: ${text}] `;
            }

            if (message.serverContent?.interrupted) {
              for (const source of sourcesRef.current) {
                try { source.stop(); } catch(e) {}
              }
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => {
            setIsLiveActive(false);
            setIsCalling(false);
          },
          onerror: (err: any) => {
            console.error("Gemini Bridge Error", err);
            const msg = err.message || "";
            if (msg.includes("Requested entity was not found")) {
              setErrorMessage("Model configuration error. Re-selecting API Key...");
              (window as any).aistudio?.openSelectKey();
            } else {
              setErrorMessage("AI Bridge error: " + (err.message || "Internal failure"));
            }
            setIsLiveActive(false);
            setIsCalling(false);
          }
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e: any) {
      console.error("Establishment failed", e);
      setErrorMessage("Failed to initiate vocal bridge: " + e.message);
      setIsLiveActive(false);
      setIsCalling(false);
    }
  };

  const stopLiveSession = async () => {
    sessionRef.current?.close();
    for (const source of sourcesRef.current) {
      try { source.stop(); } catch(e) {}
    }
    sourcesRef.current.clear();
    setIsLiveActive(false);

    if (activeLead && transcriptRef.current && onUpdateLead) {
      setIsAnalyzing(true);
      try {
        const result = await analyzeCallOutcome(activeLead, transcriptRef.current);
        onUpdateLead(activeLead.id, {
          ...result,
          summary: transcriptRef.current,
          status: 'Contacted'
        });
      } catch (err) {
        console.error("Post-call wrap failed", err);
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  const handleStartCall = async () => {
    if (mode === 'web') {
      startLiveSession();
    } else {
      setIsCalling(true);
      setCallTime(0);
      if (mode === 'bulk') executeBulk();
    }
  };

  const handleEndCall = () => {
    setIsCalling(false);
    if (mode === 'web') stopLiveSession();
  };

  const executeBulk = async () => {
    const targets = bulkTargets.map(t => ({ ...t, status: 'Pending' as const }));
    setBulkTargets(targets);
    for (let i = 0; i < targets.length; i++) {
      if (!isCalling) break;
      const updated = [...targets];
      updated[i].status = 'Calling';
      setBulkTargets([...updated]);
      await new Promise(r => setTimeout(r, 3000));
      updated[i].status = Math.random() > 0.1 ? 'Completed' : 'Failed';
      setBulkTargets([...updated]);
    }
    setIsCalling(false);
  };

  const handleManualCall = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualEntry.name || !manualEntry.phone) return;
    setActiveLead({
      id: crypto.randomUUID(),
      name: manualEntry.name,
      phone: manualEntry.phone,
      address: 'User Entry',
      type: 'Phone Call',
      status: 'New'
    });
    setMode('phone');
  };

  const handleBulkSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numbers = bulkInput.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 0);
    if (numbers.length === 0) return;
    const targets: SwarmTarget[] = numbers.map((n, idx) => ({
      id: `bulk-${idx}`,
      name: `Lead ${idx + 1}`,
      phone: n,
      status: 'Pending'
    }));
    setBulkTargets(targets);
    setMode('bulk');
    setActiveLead(null);
  };

  if (mode === 'selection') {
    return (
      <div className="max-w-4xl mx-auto space-y-10 pb-20 animate-in fade-in duration-500">
        <div className="text-center space-y-3">
          <h1 className="text-4xl font-extrabold text-slate-900 tracking-tighter uppercase">Call Command</h1>
          <p className="text-slate-500 font-medium">Select your communication protocol.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <button 
            onClick={() => {
              setMode('web');
              setActiveLead({ id: 'ai', name: 'Nexus AI Bridge', address: 'Digital Interface', type: 'Voice Call', status: 'New' });
            }}
            className="p-10 bg-white border-2 border-slate-100 rounded-[2.5rem] hover:border-emerald-500 hover:shadow-xl transition-all flex flex-col items-center text-center space-y-6 group active:scale-95"
          >
            <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-3xl flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all shadow-sm">
              <Mic2 className="w-10 h-10" />
            </div>
            <div>
              <h3 className="text-2xl font-bold text-slate-900">Gemini Neural Voice</h3>
              <p className="text-sm text-slate-500 mt-2">Natural real-time conversation via Gemini 2.5 Native Audio Bridge.</p>
            </div>
            <div className="w-full h-px bg-slate-50"></div>
            <div className="text-[10px] font-black uppercase text-emerald-500 tracking-[0.2em]">Multimodal Enabled</div>
          </button>

          <div className="p-10 bg-white border-2 border-slate-100 rounded-[2.5rem] space-y-6 shadow-sm">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center">
                <PhoneCall className="w-6 h-6" />
              </div>
              <h3 className="text-xl font-bold text-slate-900">Direct Entry</h3>
            </div>

            <form onSubmit={handleManualCall} className="space-y-3">
              <div className="flex gap-2">
                <input placeholder="Name" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none text-sm font-bold" value={manualEntry.name} onChange={e => setManualEntry({...manualEntry, name: e.target.value})} />
                <input placeholder="Number" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none text-sm font-bold" value={manualEntry.phone} onChange={e => setManualEntry({...manualEntry, phone: e.target.value})} />
              </div>
              <button className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all">Manual Dial</button>
            </form>

            <form onSubmit={handleBulkSubmit} className="space-y-3 pt-4 border-t border-slate-50">
              <textarea placeholder="Bulk coordinate input..." className="w-full h-20 bg-slate-50 p-4 rounded-xl border border-slate-100 outline-none text-sm font-medium resize-none" value={bulkInput} onChange={e => setBulkInput(e.target.value)} />
              <button className="w-full py-4 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-700 transition-all flex items-center justify-center gap-3"><Users className="w-4 h-4" /> Batch Protocol</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in fade-in zoom-in-95 duration-500 pb-32">
      {!isCalling && (
        <button onClick={() => { setMode('selection'); setActiveLead(null); setBulkTargets([]); }} className="flex items-center gap-2 text-slate-400 hover:text-slate-900 font-black text-[10px] uppercase tracking-widest transition-all px-4">
          <X className="w-4 h-4" /> Exit Command
        </button>
      )}

      {errorMessage && (
        <div className="mx-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-4 text-red-600">
           <AlertCircle className="w-5 h-5 shrink-0" />
           <p className="text-[10px] font-black uppercase tracking-tight">{errorMessage}</p>
        </div>
      )}

      <div className={`relative overflow-hidden bg-white border border-slate-200 rounded-[4rem] p-12 shadow-2xl transition-all duration-700 ${isCalling ? 'min-h-[500px]' : 'min-h-[400px]'}`}>
        {isCalling && (
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
            <div className="w-[120%] h-[120%] bg-emerald-500/5 rounded-full animate-pulse blur-3xl" />
          </div>
        )}

        <div className="relative z-10 h-full flex flex-col items-center justify-between text-center space-y-8">
          <div className="space-y-6 w-full">
            <div className={`mx-auto w-24 h-24 rounded-[2.5rem] flex items-center justify-center transition-all duration-500 shadow-xl ${isCalling ? 'bg-emerald-600 text-white' : 'bg-slate-50 text-slate-300'}`}>
              {mode === 'web' ? <Mic2 className="w-12 h-12" /> : <Phone className="w-12 h-12" />}
            </div>

            <div className="space-y-2">
              <h2 className="text-4xl font-black text-slate-900 tracking-tight uppercase">{activeLead?.name}</h2>
              <span className={`px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${mode === 'web' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>
                {mode === 'web' ? 'Neural Bridge' : 'Mobile Carrier'}
              </span>
            </div>

            {isCalling && (
               <div className="space-y-4">
                 <p className="text-7xl font-black tabular-nums text-slate-900 tracking-tighter">{formatTime(callTime)}</p>
                 <div className="min-h-[60px] max-h-[120px] overflow-y-auto px-6">
                   <p className="text-sm font-bold text-slate-400 italic leading-relaxed">
                     {transcript || 'Establishing connection...'}
                   </p>
                 </div>
               </div>
            )}
          </div>

          {!isCalling && (
            <div className="w-full max-w-sm space-y-6">
              {mode === 'web' && (
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Persona Matrix</label>
                  <div className="relative">
                    <select value={currentVoice} onChange={(e) => setCurrentVoice(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 p-4 rounded-2xl font-bold text-sm text-slate-700 outline-none pr-12 appearance-none">
                      {VOICES.map(v => <option key={v.id} value={v.id}>{v.label}</option>)}
                    </select>
                    <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 pointer-events-none" />
                  </div>
                </div>
              )}
              <button onClick={handleStartCall} className="w-full h-24 bg-emerald-600 hover:bg-emerald-700 text-white rounded-[2rem] font-black uppercase text-xl tracking-[0.2em] shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-4">
                <Sparkles className="w-6 h-6" />
                Initiate
              </button>
            </div>
          )}

          {isCalling && (
             <button onClick={handleEndCall} className="w-full max-w-sm h-24 bg-red-500 hover:bg-red-600 text-white rounded-[2rem] flex items-center justify-center gap-5 font-black uppercase text-xl tracking-[0.2em] shadow-2xl transition-all">
               <PhoneOff className="w-8 h-8" /> Hang Up
             </button>
          )}
        </div>
      </div>

      {isAnalyzing && (
        <div className="flex items-center justify-center gap-4 p-8 bg-white border border-slate-100 rounded-[2.5rem] animate-pulse">
           <Loader2 className="w-6 h-6 animate-spin text-emerald-500" />
           <p className="text-xs font-black uppercase text-slate-400 tracking-widest">Compiling post-call intelligence...</p>
        </div>
      )}
    </div>
  );
};

