  const [customText, setCustomText] = useState("");
  const [isCustomPlaying, setIsCustomPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);

  const pullFromIntel = () => {
    const saved = localStorage.getItem('nexus_ai_instructions');
    if (saved) setCustomText(saved);
  };

  const playVoice = async (text: string, voiceId: string, isCustom: boolean = false) => {
    if (previewingVoice || isCustomPlaying) return;
    if (isCustom) setIsCustomPlaying(true);
    else setPreviewingVoice(voiceId);
    setError(null);

    try {
      const base64Audio = await synthesizeSpeech(text, voiceId);

      if (!audioCtxRef.current) {
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const audioCtx = audioCtxRef.current;
      const uint8 = base64ToUint8Array(base64Audio);
      const buffer = await decodeAudioData(uint8, audioCtx, 24000, 1);

      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => {
        setPreviewingVoice(null);
        setIsCustomPlaying(false);
      };
      source.start();

    } catch (err: any) {
      console.error("Gemini TTS bridge failed", err);
      setError(err.message || "Failed to establish vocal bridge with Gemini.");
      setPreviewingVoice(null);
      setIsCustomPlaying(false);
    }
  };

  return (
    <div className="space-y-12 pb-32 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="text-center space-y-4">
        <div className="inline-flex p-4 bg-emerald-950 text-emerald-400 rounded-3xl shadow-2xl mb-4">
          <Headphones className="w-10 h-10" />
        </div>
        <h1 className="text-5xl font-black text-slate-900 tracking-tighter uppercase">
          Neural <span className="text-emerald-500">Identity</span>
        </h1>
        <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">
          Select Your AI Persona Bridge
        </p>
      </div>

      <div className="space-y-6">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Gemini High-Fidelity Voices</h3>
          {error && (
            <div className="flex items-center gap-2 text-[9px] font-black text-red-600 uppercase">
              <AlertCircle className="w-3 h-3" /> {error}
            </div>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {VOICES.map((v) => (
            <div key={v.id} className="group relative">
              <div 
                onClick={() => setSelectedVoice(v.id)}
                className={`w-full p-8 rounded-[3rem] border-4 cursor-pointer transition-all flex flex-col items-start ${
                  selectedVoice === v.id 
                    ? 'bg-emerald-950 border-emerald-950 text-white shadow-2xl scale-[1.02]' 
                    : 'bg-white border-slate-100 text-slate-400 hover:border-emerald-200 shadow-sm'
                }`}
              >
                <div className="flex items-center gap-3 mb-2">
                  <Volume2 className={`w-6 h-6 ${selectedVoice === v.id ? 'text-emerald-400' : 'text-slate-200'}`} />
                  <span className="text-2xl font-black uppercase tracking-tighter">{v.label}</span>
                </div>
                <span className="text-[11px] font-bold uppercase tracking-tight opacity-50 mb-6">{v.desc}</span>

                <button 
                  onClick={(e) => { e.stopPropagation(); playVoice(v.test, v.id); }}
                  disabled={previewingVoice !== null}
                  className={`flex items-center gap-3 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    selectedVoice === v.id 
                      ? 'bg-emerald-500 text-emerald-950 hover:bg-emerald-400' 
                      : 'bg-slate-50 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'
                  }`}
                >
                  {previewingVoice === v.id ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : (
                    <Play className="w-4 h-4 fill-current" />
                  )}
                  Preview
                </button>

                {selectedVoice === v.id && (
                  <div className="absolute top-8 right-8 text-emerald-400 animate-in zoom-in duration-300">
                    <CheckCircle2 className="w-8 h-8" />
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 p-10 md:p-14 shadow-sm space-y-10">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="flex items-center gap-5">
            <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl">
              <MessageSquare className="w-8 h-8" />
            </div>
            <div>
              <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Script Rehearsal</h2>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Test instructions via Gemini TTS</p>
            </div>
          </div>
          <button onClick={pullFromIntel} className="flex items-center gap-2 px-6 py-3 bg-slate-50 text-slate-400 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-emerald-50 hover:text-emerald-600 transition-all border border-slate-100">
            <RefreshCcw className="w-3 h-3" /> Sync Instruction
          </button>
        </div>

        <div className="relative group">
          <textarea value={customText} onChange={(e) => setCustomText(e.target.value)} placeholder="Type rehearsal script..." className="w-full h-48 bg-slate-50 border-4 border-slate-50 rounded-[2.5rem] p-10 text-xl font-bold text-slate-800 focus:border-emerald-500 focus:bg-white outline-none transition-all resize-none shadow-inner" />
