interface LeadFinderProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  onCallLead: (lead: Lead) => void;
}

const LeadFinder: React.FC<LeadFinderProps> = ({ leads, setLeads, onCallLead }) => {
  const [query, setQuery] = useState('Schools');
  const [location, setLocation] = useState('Nairobi, Kenya');
  const [projectName, setProjectName] = useState('Campaign Alpha');
  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<Lead[]>([]);

  const handleScan = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!query || !location) return;
    setLoading(true);
    setError(null);
    setResults([]);
    try {
      const { leads: fetched } = await searchLeadsWithGemini(query, location);
      if (fetched.length > 0) {
        // Tag leads with project name immediately
        const tagged = fetched.map(l => ({ ...l, projectName }));
        setResults(tagged);
      } else {
        setError("No new leads found for this criteria.");
      }
    } catch (err) {
      setError("Search failed. Check your API configuration.");
    } finally {
      setLoading(false);
    }
  };

  const handleIngest = async (lead: Lead) => {
    try {
      const enriched = await enrichLeadsWithGemini([lead]);
      const savedLead = { ...enriched[0], projectName };
      setLeads(prev => [savedLead, ...prev]);
      setResults(prev => prev.filter(r => r.id !== lead.id));
    } catch (e) {
      setLeads(prev => [{ ...lead, projectName }, ...prev]);
      setResults(prev => prev.filter(r => r.id !== lead.id));
    }
  };

  const downloadCSV = () => {
    const dataToExport = results.length > 0 ? results : leads;
    if (dataToExport.length === 0) return;

    setExporting(true);
    const headers = ['Project', 'Name', 'Type', 'Address', 'Phone', 'Email', 'Maps Link'];
    const csvContent = [
      headers.join(','),
      ...dataToExport.map(l => [
        `"${(l.projectName || 'Unassigned').replace(/"/g, '""')}"`,
        `"${l.name.replace(/"/g, '""')}"`,
        `"${l.type.replace(/"/g, '""')}"`,
        `"${l.address.replace(/"/g, '""')}"`,
        `"${(l.phone || 'N/A').replace(/"/g, '""')}"`,
        `"${(l.email || 'N/A').replace(/"/g, '""')}"`,
        `"${(l.googleMapsUri || 'N/A').replace(/"/g, '""')}"`
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `Nexus_Leads_${projectName.replace(/\s+/g, '_')}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setTimeout(() => setExporting(false), 1000);
  };

  const activeData = results.length > 0 ? results : leads;

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-500">
      <div className="space-y-2">
        <h1 className="text-4xl font-black text-slate-950 tracking-tight uppercase">
          Lead <span className="text-emerald-600">Scout</span>
        </h1>
        <p className="text-sm font-medium text-slate-500">Organize your data into projects for better conversion tracking.</p>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 p-6 md:p-8 shadow-sm space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Current Project</label>
            <div className="relative">
              <input 
                type="text" 
                value={projectName} 
                onChange={e => setProjectName(e.target.value)}
                placeholder="Campaign Alpha"
                className="w-full h-14 bg-slate-50 border border-slate-200 rounded-xl px-12 font-bold text-slate-800 focus:border-emerald-500 focus:bg-white outline-none transition-all"
              />
              <FolderPlus className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Industry</label>
            <div className="relative">
              <input 
                type="text" 
                value={query} 
                onChange={e => setQuery(e.target.value)}
