        <div className="flex justify-between items-center pt-4 border-t border-slate-100">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400">
               <Database className="w-5 h-5" />
             </div>
             <div>
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Global Database</p>
               <p className="text-sm font-black text-slate-900 uppercase tracking-tighter">{activeData.length} Targets Sync'd</p>
             </div>
          </div>
          <button 
            onClick={downloadCSV}
            disabled={exporting || activeData.length === 0}
            className="px-6 py-3 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-black transition-all flex items-center gap-2 shadow-lg disabled:opacity-30"
          >
            {exporting ? <Loader2 className="w-3 h-3 animate-spin" /> : <FileDown className="w-3 h-3" />}
            Export Project CSV
          </button>
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex items-center justify-between px-2">
           <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Scouted Intelligence Results</h3>
           {results.length > 0 && (
             <button onClick={() => setResults([])} className="text-[10px] font-black text-red-500 uppercase tracking-widest flex items-center gap-1 hover:underline">
               <Trash2 className="w-3 h-3" /> Clear Queue
             </button>
           )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {activeData.map((lead) => (
            <div key={lead.id} className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm group hover:border-emerald-200 transition-all flex flex-col justify-between">
              <div className="space-y-4">
                <div className="flex justify-between items-start">
                  <div className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ${lead.status === 'New' ? 'bg-emerald-50 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>
                    {lead.projectName || 'Unassigned'}
                  </div>
                  <Target className="w-5 h-5 text-slate-100 group-hover:text-emerald-100 transition-colors" />
                </div>

                <div>
                  <h4 className="text-2xl font-black text-slate-950 tracking-tighter uppercase leading-none">{lead.name}</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">{lead.type}</p>
                </div>

                <div className="space-y-3 pt-2">
                  <div className="flex items-center gap-3 text-slate-500">
                    <MapPin className="w-4 h-4 shrink-0 text-slate-300" />
                    <span className="text-xs font-bold leading-tight">{lead.address}</span>
                  </div>
                  {lead.phone && (
                    <div className="flex items-center gap-3 text-slate-500">
                      <Phone className="w-4 h-4 shrink-0 text-slate-300" />
                      <span className="text-xs font-bold">{lead.phone}</span>
                    </div>
                  )}
                  {lead.email && (
                    <div className="flex items-center gap-3 text-slate-500">
                      <Mail className="w-4 h-4 shrink-0 text-slate-300" />
                      <span className="text-xs font-bold truncate">{lead.email}</span>
                    </div>
                  )}
                </div>
              </div>

              <div className="mt-8 pt-6 border-t border-slate-50 flex gap-3">
                {results.some(r => r.id === lead.id) ? (
                  <button 
                    onClick={() => handleIngest(lead)}
                    className="flex-1 h-12 bg-emerald-950 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all flex items-center justify-center gap-2"
                  >
                    <Download className="w-4 h-4" /> Save To CRM
                  </button>
                ) : (
                  <button 
                    onClick={() => onCallLead(lead)}
                    className="flex-1 h-12 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all flex items-center justify-center gap-2"
                  >
                    <Zap className="w-4 h-4 text-emerald-400" /> Initiate Link
                  </button>
                )}
              </div>
            </div>
          ))}

          {activeData.length === 0 && (
            <div className="col-span-full py-32 flex flex-col items-center justify-center border-4 border-dashed border-slate-50 rounded-[3rem] opacity-30">
              <Search className="w-16 h-16 text-slate-300 mb-6" />
              <p className="text-sm font-black text-slate-400 uppercase tracking-[0.4em]">Awaiting Scout Command</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

