import React, { useState, useEffect } from 'react';
import { Search, Database, Phone, Settings, LayoutGrid, Activity, Mic2, PhoneCall } from 'lucide-react';
import LeadFinder from './components/LeadFinder';
import CallAgent from './components/CallAgent';
import CallInterface from './components/CallInterface';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import KnowledgeBase from './components/KnowledgeBase';
import SettingsTab from './components/SettingsTab';
import { AppTab, Lead, Project } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.SCOUT);
  const [activeLead, setActiveLead] = useState<Lead | null>(null);
  const [selectedVoice, setSelectedVoice] = useState('Rachel');

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('nexus_projects_v2');
    if (saved) return JSON.parse(saved);
    return [{
      id: 'default',
      name: 'Default Campaign',
      description: 'System generated campaign',
      leads: [],
      aiInstructions: '',
      createdAt: new Date().toISOString()
    }];
  });

  const [currentProjectId, setCurrentProjectId] = useState<string>(() => {
    return localStorage.getItem('nexus_active_project') || 'default';
  });

  useEffect(() => {
    localStorage.setItem('nexus_projects_v2', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem('nexus_active_project', currentProjectId);
  }, [currentProjectId]);

  const currentProject = projects.find(p => p.id === currentProjectId) || projects[0];

  const handleCallLead = (lead: Lead) => {
    setActiveLead(lead);
    setActiveTab(AppTab.CALL);
  };

  const updateLead = (leadId: string, updates: Partial<Lead>) => {
    setProjects(prev => prev.map(proj => ({
      ...proj,
      leads: proj.leads.map(l => l.id === leadId ? { ...l, ...updates } : l)
    })));
  };

  const handleUpdateProjects = (updatedProjects: Project[]) => {
    setProjects(updatedProjects);
  };

  return (
    <div className="h-screen w-full bg-[#f8fafc] text-slate-900 font-sans flex flex-col overflow-hidden">
      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-32">
        <div className="max-w-4xl mx-auto p-4 md:p-8 animate-in fade-in duration-500">

          {activeTab === AppTab.SCOUT && (
            <LeadFinder 
              projects={projects} 
              setProjects={handleUpdateProjects}
              currentProjectId={currentProjectId}
              setCurrentProjectId={setCurrentProjectId}
              onCallLead={handleCallLead} 
            />
          )}

          {activeTab === AppTab.INTEL && (
            <KnowledgeBase 
              project={currentProject}
              onUpdateProject={(updates) => {
                setProjects(prev => prev.map(p => p.id === currentProjectId ? { ...p, ...updates } : p));
              }}
            />
          )}

          {activeTab === AppTab.VOICES && (
            <CallAgent 
              selectedVoice={selectedVoice}
              setSelectedVoice={setSelectedVoice}
            />
          )}

          {activeTab === AppTab.CALL && (
            <CallInterface 
              activeLead={activeLead}
              projects={projects}
              currentProjectId={currentProjectId}
              selectedVoice={selectedVoice}
              onUpdateLead={updateLead}
              onSelectLead={setActiveLead}
            />
          )}

          {activeTab === AppTab.DATA && (
            <AnalyticsDashboard leads={currentProject.leads} onCallLead={handleCallLead} />
          )}

          {activeTab === AppTab.SETUP && (
            <SettingsTab />
          )}
        </div>
      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-2 py-3 flex items-center justify-around z-[100] shadow-[0_-4px_20px_rgba(0,0,0,0.03)] overflow-x-auto">
        <NavButton active={activeTab === AppTab.SCOUT} onClick={() => setActiveTab(AppTab.SCOUT)} icon={Search} label="SCOUT" />
        <NavButton active={activeTab === AppTab.INTEL} onClick={() => setActiveTab(AppTab.INTEL)} icon={LayoutGrid} label="INTEL" />
        <NavButton active={activeTab === AppTab.VOICES} onClick={() => setActiveTab(AppTab.VOICES)} icon={Mic2} label="VOICES" />
        <NavButton active={activeTab === AppTab.CALL} onClick={() => setActiveTab(AppTab.CALL)} icon={PhoneCall} label="CALL" />
        <NavButton active={activeTab === AppTab.DATA} onClick={() => setActiveTab(AppTab.DATA)} icon={Activity} label="DATA" />
        <NavButton active={activeTab === AppTab.SETUP} onClick={() => setActiveTab(AppTab.SETUP)} icon={Settings} label="SETUP" />
      </nav>
    </div>
  );
};

const NavButton = ({ active, onClick, icon: Icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 min-w-[60px] transition-all px-2 ${active ? 'text-emerald-600' : 'text-slate-400'}`}>
    <Icon className={`w-5 h-5 ${active ? 'stroke-[2.5px]' : 'stroke-[1.5px]'}`} />
    <span className="text-[9px] font-black uppercase tracking-tight">{label}</span>
  </button>
);

export default App;

import React, { useState } from 'react';
import { Search, MapPin, Loader2, Zap, Info, Target, Download, Trash2, Mail, Phone, FileDown, FolderPlus, PlusCircle } from 'lucide-react';
import { Lead, Project } from '../types';
import { searchLeadsWithGemini, enrichLeadsWithGemini } from '../services/gemini';

interface LeadFinderProps {
  projects: Project[];
  setProjects: (projects: Project[]) => void;
  currentProjectId: string;
  setCurrentProjectId: (id: string) => void;
  onCallLead: (lead: Lead) => void;
}

const LeadFinder: React.FC<LeadFinderProps> = ({ projects, setProjects, currentProjectId, setCurrentProjectId, onCallLead }) => {
  const [query, setQuery] = useState('Schools');
  const [location, setLocation] = useState('Nairobi, Kenya');
  const [isCreating, setIsCreating] = useState(false);
  const [newProjectName, setNewProjectName] = useState('');

  const [loading, setLoading] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<Lead[]>([]);

  const activeProject = projects.find(p => p.id === currentProjectId) || projects[0];

  const handleCreateProject = () => {
    if (!newProjectName.trim()) return;
    const newProj: Project = {
      id: crypto.randomUUID(),
      name: newProjectName,
      description: '',
      leads: [],
      aiInstructions: '',
      createdAt: new Date().toISOString()
    };
    setProjects([...projects, newProj]);
    setCurrentProjectId(newProj.id);
    setNewProjectName('');
    setIsCreating(false);
  };

  const handleScan = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!query || !location) return;
    setLoading(true);
    setError(null);
    setResults([]);
    try {
      const { leads: fetched } = await searchLeadsWithGemini(query, location);
      if (fetched.length > 0) {
        setResults(fetched.map(l => ({ ...l, projectName: activeProject.name })));
      } else {
        setError("No new leads found for this criteria.");
      }
    } catch (err) {
      setError("Search failed. Check your API configuration.");
    } finally {
      setLoading(false);
    }
  };

  const handleIngest = async (lead: Lead) => {
    try {
      const enriched = await enrichLeadsWithGemini([lead]);
      const savedLead = { ...enriched[0], projectName: activeProject.name, status: 'New' as const };

      setProjects(projects.map(p => 
        p.id === currentProjectId 
          ? { ...p, leads: [savedLead, ...p.leads] } 
          : p
      ));

      setResults(prev => prev.filter(r => r.id !== lead.id));
    } catch (e) {
      const savedLead = { ...lead, projectName: activeProject.name, status: 'New' as const };
      setProjects(projects.map(p => 
        p.id === currentProjectId 
          ? { ...p, leads: [savedLead, ...p.leads] } 
          : p
      ));
      setResults(prev => prev.filter(r => r.id !== lead.id));
    }
  };

  const downloadCSV = () => {
    const dataToExport = activeProject.leads;
    if (dataToExport.length === 0) return;

    setExporting(true);
    const headers = ['Project', 'Name', 'Type', 'Address', 'Phone', 'Email', 'Status'];
    const csvContent = [
      headers.join(','),
      ...dataToExport.map(l => [
        `"${activeProject.name}"`,
        `"${l.name.replace(/"/g, '""')}"`,
        `"${l.type.replace(/"/g, '""')}"`,
        `"${l.address.replace(/"/g, '""')}"`,
        `"${(l.phone || 'N/A')}"`,
        `"${(l.email || 'N/A')}"`,
        `"${l.status}"`
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `${activeProject.name}_leads.csv`);
    link.click();
    setTimeout(() => setExporting(false), 1000);
  };

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-2">
          <h1 className="text-4xl font-black text-slate-950 tracking-tight uppercase">
            Lead <span className="text-emerald-600">Scout</span>
          </h1>
          <p className="text-sm font-medium text-slate-500">Identify and capture coordinates for your next campaign.</p>
        </div>

        <div className="flex items-center gap-3">
          <div className="relative">
            <select 
              value={currentProjectId}
              onChange={(e) => setCurrentProjectId(e.target.value)}
              className="h-12 bg-white border border-slate-200 rounded-xl px-4 pr-10 font-bold text-xs text-slate-700 outline-none appearance-none shadow-sm"
            >
              {projects.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
            <FolderPlus className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
          </div>
          <button 
            onClick={() => setIsCreating(true)}
            className="h-12 w-12 bg-emerald-950 text-white rounded-xl flex items-center justify-center hover:bg-black transition-all shadow-lg"
          >
            <PlusCircle className="w-6 h-6" />
          </button>
        </div>
      </div>

      {isCreating && (
        <div className="bg-emerald-50 border-2 border-emerald-100 rounded-2xl p-6 animate-in slide-in-from-top-4 duration-300">
          <div className="flex gap-4">
            <input 
              autoFocus
              value={newProjectName}
              onChange={e => setNewProjectName(e.target.value)}
              placeholder="Enter Campaign Name..."
              className="flex-1 h-12 bg-white rounded-xl px-4 font-bold text-sm outline-none border border-emerald-200"
              onKeyDown={e => e.key === 'Enter' && handleCreateProject()}
            />
            <button onClick={handleCreateProject} className="px-6 h-12 bg-emerald-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest">Create Project</button>
            <button onClick={() => setIsCreating(false)} className="px-4 h-12 bg-white text-slate-400 rounded-xl font-black text-[10px] uppercase">Cancel</button>
          </div>
        </div>
      )}

      <div className="bg-white rounded-3xl border border-slate-200 p-8 shadow-sm space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Industry / Category</label>
            <div className="relative">
              <input type="text" value={query} onChange={e => setQuery(e.target.value)} className="w-full h-14 bg-slate-50 border border-slate-200 rounded-xl px-12 font-bold text-slate-800 focus:border-emerald-500 focus:bg-white outline-none transition-all" />
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Location Coordinates</label>
            <div className="relative">
              <input type="text" value={location} onChange={e => setLocation(e.target.value)} className="w-full h-14 bg-slate-50 border border-slate-200 rounded-xl px-12 font-bold text-slate-800 focus:border-emerald-500 focus:bg-white outline-none transition-all" />
              <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
            </div>
          </div>
        </div>

        <button onClick={() => handleScan()} disabled={loading} className="w-full h-16 bg-emerald-600 text-white rounded-2xl font-black uppercase text-sm tracking-widest shadow-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-3">
          {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-6 h-6 fill-current" />}
          {loading ? 'Decrypting Map Data...' : 'Scout Area'}
        </button>

        <div className="flex justify-between items-center pt-4 border-t border-slate-100">
          <div className="flex items-center gap-3">
             <div className="text-emerald-500 font-black text-xl">{activeProject.leads.length}</div>
             <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Campaign Targets</div>
          </div>
          <button onClick={downloadCSV} disabled={activeProject.leads.length === 0} className="px-6 py-3 text-slate-400 hover:text-slate-900 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2">
            <FileDown className="w-4 h-4" /> Export Results
          </button>
        </div>
      </div>

      <div className="space-y-6">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-2">Fresh Intel Queue</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {results.map((lead) => (
            <div key={lead.id} className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm group hover:border-emerald-200 transition-all flex flex-col justify-between">
              <div className="space-y-4">
                <div className="flex justify-between">
                  <span className="text-[9px] font-black uppercase tracking-widest bg-emerald-50 text-emerald-600 px-3 py-1 rounded-lg">Potential Lead</span>
                  <Target className="w-5 h-5 text-slate-200" />
                </div>
                <div>
                  <h4 className="text-2xl font-black text-slate-950 tracking-tighter uppercase leading-tight">{lead.name}</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">{lead.type}</p>
                </div>
                <div className="flex items-start gap-3 text-slate-500">
                  <MapPin className="w-4 h-4 shrink-0 mt-0.5 text-slate-300" />
                  <span className="text-xs font-bold leading-tight">{lead.address}</span>
                </div>
              </div>
              <button onClick={() => handleIngest(lead)} className="mt-8 w-full h-12 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all flex items-center justify-center gap-2">
                <Download className="w-4 h-4" /> Add to Campaign
              </button>
            </div>
          ))}
          {results.length === 0 && (
            <div className="col-span-full py-20 text-center opacity-30 border-4 border-dashed border-slate-100 rounded-[3rem]">
              <Target className="w-12 h-12 mx-auto mb-4 text-slate-300" />
              <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Awaiting Scout Directives</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

